import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function identifyEquipment(imageAsBase64: string): Promise<any> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: imageAsBase64,
          },
        },
        {
          text: "Identify this STEM equipment. Categorize it into: 'Working Condition', 'Repairable', or 'E-Waste'. Provide the specific name of the item and a brief justification for the category. Output as JSON.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          itemName: { type: Type.STRING },
          category: { 
            type: Type.STRING, 
            description: "Must be one of: Working Condition, Repairable, E-Waste" 
          },
          justification: { type: Type.STRING },
          estimatedPoints: { type: Type.NUMBER }
        },
        required: ["itemName", "category", "estimatedPoints"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return null;
  }
}

export async function getReuseSuggestions(itemDescription: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest 3 creative and educational ways to reuse this obsolete STEM equipment in a school environment: ${itemDescription}`,
    config: {
      systemInstruction: "You are a creative STEM educator specializing in upcycling and refurbishing technology."
    }
  });

  return response.text;
}

import React, { useState } from 'react';
import { CategoryType, EquipmentItem } from '../types';
import { POINT_VALUES } from '../constants';

interface PointCalculatorProps {
  onUpdatePoints: (points: number) => void;
}

const PointCalculator: React.FC<PointCalculatorProps> = ({ onUpdatePoints }) => {
  const [items, setItems] = useState<EquipmentItem[]>([]);
  const [currentCategory, setCurrentCategory] = useState<CategoryType>(CategoryType.WORKING);
  const [quantity, setQuantity] = useState<number>(1);
  const [itemName, setItemName] = useState<string>('');

  const addItem = () => {
    if (!itemName) return;

    let points = 0;
    switch (currentCategory) {
      case CategoryType.WORKING: points = POINT_VALUES.WORKING_KIT * quantity; break;
      case CategoryType.REPAIRABLE: points = POINT_VALUES.FUNCTIONAL_PART * quantity; break;
      case CategoryType.E_WASTE: points = POINT_VALUES.BATTERY_UNIT * quantity; break;
      case CategoryType.LEGO: points = POINT_VALUES.LEGO_PER_KG * quantity; break;
    }

    const newItem: EquipmentItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: itemName,
      category: currentCategory,
      points,
      quantity,
    };

    const newItems = [...items, newItem];
    setItems(newItems);
    onUpdatePoints(newItems.reduce((acc, item) => acc + item.points, 0));

    // Reset inputs
    setItemName('');
    setQuantity(1);
  };

  const removeItem = (id: string) => {
    const newItems = items.filter(i => i.id !== id);
    setItems(newItems);
    onUpdatePoints(newItems.reduce((acc, item) => acc + item.points, 0));
  };

  return (
    <section id="calculator" className="bg-white rounded-2xl shadow-xl border border-slate-100 p-6 md:p-8">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-2">
        <span className="p-2 bg-blue-100 text-blue-600 rounded-lg">🧮</span>
        STEM Support Points Calculator
      </h2>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="md:col-span-2">
          <label className="block text-sm font-medium text-slate-700 mb-1">Item Name</label>
          <input 
            type="text" 
            value={itemName}
            onChange={(e) => setItemName(e.target.value)}
            placeholder="e.g. LEGO Mindstorms EV3, Micro:bit..."
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
          <select 
            value={currentCategory}
            onChange={(e) => setCurrentCategory(e.target.value as CategoryType)}
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
          >
            {Object.values(CategoryType).map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">
            {currentCategory === CategoryType.LEGO ? 'Weight (KG)' : 'Quantity'}
          </label>
          <div className="flex gap-2">
            <input 
              type="number" 
              value={quantity}
              onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 0))}
              className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
            />
            <button 
              onClick={addItem}
              className="bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-200"
            >
              Add
            </button>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="border-b border-slate-100">
              <th className="py-3 px-4 font-semibold text-slate-600 text-sm">Item</th>
              <th className="py-3 px-4 font-semibold text-slate-600 text-sm">Category</th>
              <th className="py-3 px-4 font-semibold text-slate-600 text-sm">Qty/Wt</th>
              <th className="py-3 px-4 font-semibold text-slate-600 text-sm">Est. Points</th>
              <th className="py-3 px-4 text-sm"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {items.length === 0 ? (
              <tr>
                <td colSpan={5} className="py-12 text-center text-slate-400 italic">
                  No items added yet. Estimate your school's credit above.
                </td>
              </tr>
            ) : (
              items.map(item => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="py-3 px-4 text-slate-800 font-medium">{item.name}</td>
                  <td className="py-3 px-4">
                    <span className={`text-xs font-semibold px-2 py-1 rounded-full ${
                      item.category === CategoryType.WORKING ? 'bg-green-100 text-green-700' :
                      item.category === CategoryType.REPAIRABLE ? 'bg-orange-100 text-orange-700' :
                      'bg-red-100 text-red-700'
                    }`}>
                      {item.category}
                    </span>
                  </td>
                  <td className="py-3 px-4 text-slate-600">{item.quantity}{item.category === CategoryType.LEGO ? 'kg' : ''}</td>
                  <td className="py-3 px-4 text-emerald-600 font-bold">+{item.points}</td>
                  <td className="py-3 px-4 text-right">
                    <button 
                      onClick={() => removeItem(item.id)}
                      className="text-slate-400 hover:text-red-500 transition-colors"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                      </svg>
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <div className="mt-8 pt-8 border-t border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="bg-emerald-50 px-6 py-4 rounded-xl border border-emerald-100">
          <p className="text-emerald-800 font-medium text-sm">Estimated Total Credit</p>
          <p className="text-3xl font-black text-emerald-600">
            {items.reduce((acc, item) => acc + item.points, 0)} <span className="text-sm font-bold uppercase tracking-widest">Points</span>
          </p>
        </div>
        <button className="w-full md:w-auto bg-slate-800 text-white px-8 py-4 rounded-xl font-bold hover:bg-slate-900 transition-all transform hover:-translate-y-1 shadow-xl">
          Request Pick-up & Audit
        </button>
      </div>
    </section>
  );
};

export default PointCalculator;

