import React, { useState, useRef } from 'react';
import { identifyEquipment, getReuseSuggestions } from '../services/geminiService';

const AIAssistant: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [suggestions, setSuggestions] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    setResult(null);
    setSuggestions('');

    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const identification = await identifyEquipment(base64);
      setResult(identification);

      if (identification) {
        const ideas = await getReuseSuggestions(`${identification.itemName} in ${identification.category} state`);
        setSuggestions(ideas);
      }
      setLoading(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <section className="mt-16 bg-gradient-to-br from-slate-900 to-indigo-950 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
      {/* Decorative background circles */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl -mr-32 -mt-32"></div>
      <div className="absolute bottom-0 left-0 w-64 h-64 bg-blue-500/10 rounded-full blur-3xl -ml-32 -mb-32"></div>

      <div className="relative z-10 flex flex-col md:flex-row gap-12 items-center">
        <div className="flex-1">
          <div className="inline-flex items-center gap-2 bg-indigo-500/20 px-4 py-1 rounded-full border border-indigo-400/30 text-indigo-200 text-sm font-semibold mb-6">
            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-pulse"></span>
            Powered by Gemini AI
          </div>
          <h2 className="text-4xl font-bold mb-4">Unsure what to do with an item?</h2>
          <p className="text-indigo-100/80 text-lg mb-8 leading-relaxed">
            Scan your old robots or components using our AI helper. We'll help you categorize them for points and suggest creative educational reuse projects for your students.
          </p>

          <div className="flex flex-wrap gap-4">
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={loading}
              className="bg-white text-indigo-950 px-8 py-4 rounded-xl font-bold hover:bg-indigo-50 transition-all flex items-center gap-3 disabled:opacity-50"
            >
              {loading ? (
                <svg className="animate-spin h-5 w-5 text-indigo-950" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              )}
              {loading ? 'Analyzing...' : 'Snap & Scan Item'}
            </button>
            <input 
              type="file" 
              accept="image/*" 
              capture="environment" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
            />
          </div>
        </div>

        <div className="flex-1 w-full max-w-md">
          {loading ? (
             <div className="bg-white/5 border border-white/10 rounded-2xl p-8 text-center backdrop-blur-sm animate-pulse">
                <div className="h-12 w-12 bg-indigo-500/20 rounded-full mx-auto mb-4"></div>
                <p className="text-indigo-200">Our AI is examining the hardware structure...</p>
             </div>
          ) : result ? (
            <div className="bg-white/10 border border-white/20 rounded-2xl p-6 backdrop-blur-md">
              <div className="flex justify-between items-start mb-4">
                <h3 className="text-2xl font-bold">{result.itemName}</h3>
                <span className="bg-emerald-500 text-white px-3 py-1 rounded-full text-xs font-bold">
                  {result.category}
                </span>
              </div>
              <div className="mb-6">
                <p className="text-indigo-200 text-sm mb-2">Estimated Value:</p>
                <p className="text-3xl font-black text-emerald-400">+{result.estimatedPoints} Points</p>
              </div>
              <div className="space-y-4">
                <div className="p-3 bg-white/5 rounded-lg border border-white/5">
                   <p className="text-xs font-bold text-indigo-300 uppercase mb-1">Observation</p>
                   <p className="text-sm italic">"{result.justification}"</p>
                </div>
                {suggestions && (
                  <div className="p-3 bg-indigo-500/10 rounded-lg border border-indigo-500/20">
                    <p className="text-xs font-bold text-indigo-300 uppercase mb-1">Classroom Reuse Ideas</p>
                    <div className="text-sm prose prose-invert max-w-none prose-p:my-1">
                      {suggestions.split('\n').map((line, i) => (
                        <p key={i}>{line}</p>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="bg-white/5 border border-white/10 rounded-2xl p-12 text-center backdrop-blur-sm">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-indigo-400/30 mx-auto mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              <p className="text-indigo-300">Analysis results will appear here after you scan an item.</p>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

export default AIAssistant;

