import React, { useState } from 'react';
import { ICONS } from '../constants';
import { LearningTrack, Subcategory } from '../types';

interface SidebarProps {
  currentView: string;
  onViewChange: (view: any) => void;
  tracks: LearningTrack[];
  onTracksReorder: (tracks: LearningTrack[]) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, onViewChange, tracks, onTracksReorder }) => {
  const [draggedTrackIndex, setDraggedTrackIndex] = useState<number | null>(null);
  const [draggedSubIndex, setDraggedSubIndex] = useState<{ trackIdx: number, subIdx: number } | null>(null);
  const [expandedTrackIds, setExpandedTrackIds] = useState<Set<string>>(new Set(tracks.map(t => t.id)));

  const toggleTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newExpanded = new Set(expandedTrackIds);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedTrackIds(newExpanded);
  };

  // Track Reordering
  const onTrackDragStart = (e: React.DragEvent, index: number) => {
    setDraggedTrackIndex(index);
    setDraggedSubIndex(null);
  };

  const onTrackDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedTrackIndex === null || draggedTrackIndex === index) return;

    const newTracks = [...tracks];
    const item = newTracks[draggedTrackIndex];
    newTracks.splice(draggedTrackIndex, 1);
    newTracks.splice(index, 0, item);

    setDraggedTrackIndex(index);
    onTracksReorder(newTracks);
  };

  // Subcategory Reordering
  const onSubDragStart = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.stopPropagation();
    setDraggedSubIndex({ trackIdx, subIdx });
    setDraggedTrackIndex(null);
  };

  const onSubDragOver = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.preventDefault();
    e.stopPropagation();
    if (!draggedSubIndex) return;
    if (draggedSubIndex.trackIdx !== trackIdx) return; // Only allow reordering within same track
    if (draggedSubIndex.subIdx === subIdx) return;

    const newTracks = JSON.parse(JSON.stringify(tracks)) as LearningTrack[];
    const track = newTracks[trackIdx];
    if (!track.subcategories) return;

    const item = track.subcategories[draggedSubIndex.subIdx];
    track.subcategories.splice(draggedSubIndex.subIdx, 1);
    track.subcategories.splice(subIdx, 0, item);

    setDraggedSubIndex({ trackIdx, subIdx });
    onTracksReorder(newTracks);
  };

  const onDragEnd = () => {
    setDraggedTrackIndex(null);
    setDraggedSubIndex(null);
  };

  return (
    <div className="w-80 h-screen bg-white border-r border-slate-200 flex flex-col py-8 px-4 relative shadow-sm shrink-0">
      {/* Logo */}
      <div className="flex items-center gap-3 px-2 mb-10 overflow-hidden whitespace-nowrap">
        <div className="w-10 h-10 shrink-0 bg-purple-700 rounded-xl flex items-center justify-center text-white shadow-lg shadow-purple-200">
          <div className="w-5 h-5 border-2 border-white rounded-lg flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>
        <div>
          <h2 className="text-sm font-black text-slate-900 leading-none tracking-tight">LEARNING</h2>
          <p className="text-[11px] font-bold text-purple-700 tracking-widest mt-0.5">GALLERY</p>
        </div>
      </div>

      {/* Main Nav */}
      <div className="space-y-1">
        <button
          onClick={() => onViewChange('home')}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all overflow-hidden whitespace-nowrap ${
            currentView === 'home' 
            ? 'bg-purple-700 text-white shadow-lg shadow-purple-200' 
            : 'text-slate-700 hover:bg-slate-100'
          }`}
        >
          {ICONS.Home}
          <span>HOME PAGE</span>
        </button>
      </div>

      {/* Learning Tracks Section */}
      <div className="mt-10 flex-1 overflow-y-auto no-scrollbar">
        <h3 className="px-4 text-[11px] font-black text-slate-500 uppercase tracking-widest mb-6">LEARNING TRACKS</h3>
        <div className="space-y-2">
          {tracks.map((track, tIdx) => (
            <div key={track.id} className="space-y-1">
              {/* Track Item */}
              <div
                draggable
                onDragStart={(e) => onTrackDragStart(e, tIdx)}
                onDragOver={(e) => onTrackDragOver(e, tIdx)}
                onDragEnd={onDragEnd}
                onClick={(e) => toggleTrack(e, track.id)}
                className={`group flex items-center gap-3 px-4 py-3.5 rounded-xl cursor-grab active:cursor-grabbing transition-all border border-transparent hover:bg-slate-50 hover:border-slate-200 ${
                  draggedTrackIndex === tIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'
                }`}
              >
                <div className="text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity">
                   <div className="grid grid-cols-2 gap-0.5">{Array(4).fill(0).map((_,i) => <div key={i} className="w-0.5 h-0.5 bg-current rounded-full" />)}</div>
                </div>
                <span className="text-xl shrink-0">{track.icon}</span>
                <span className="flex-1 text-[12px] font-bold text-slate-900 tracking-wide uppercase truncate">
                  {track.title}
                </span>
                <div className={`text-slate-400 transition-transform duration-300 ${expandedTrackIds.has(track.id) ? 'rotate-180' : ''}`}>
                  {ICONS.ChevronDown}
                </div>
              </div>

              {/* Subcategories */}
              {expandedTrackIds.has(track.id) && track.subcategories && track.subcategories.length > 0 && (
                <div className="ml-10 space-y-1 animate-in slide-in-from-top-2 duration-200">
                  {track.subcategories.map((sub, sIdx) => (
                    <div
                      key={sub.id}
                      draggable
                      onDragStart={(e) => onSubDragStart(e, tIdx, sIdx)}
                      onDragOver={(e) => onSubDragOver(e, tIdx, sIdx)}
                      onDragEnd={onDragEnd}
                      className={`group flex items-center gap-3 px-4 py-2.5 rounded-lg cursor-grab active:cursor-grabbing transition-all border border-transparent hover:bg-slate-50 hover:border-slate-200 ${
                        draggedSubIndex?.trackIdx === tIdx && draggedSubIndex?.subIdx === sIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'
                      }`}
                    >
                      <div className="w-1.5 h-1.5 rounded-full bg-slate-300 group-hover:bg-purple-500 transition-colors" />
                      <span className="text-[11px] font-bold text-slate-600 tracking-wide uppercase truncate group-hover:text-slate-900">
                        {sub.title}
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Admin Login */}
      <button className="mt-auto mx-2 flex items-center justify-center gap-2 py-3.5 px-4 rounded-xl bg-slate-900 text-white text-[11px] font-bold uppercase tracking-widest hover:bg-purple-800 transition-all shadow-md whitespace-nowrap overflow-hidden">
        {ICONS.Admin}
        ADMIN LOGIN
      </button>
    </div>
  );
};

