                    {/* Projects in this track but without specific subcategory */}
                    {trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
