                ) : (
                  <div>
                    {trackProjects.length > 0 ? (
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                        {trackProjects.map((project) => renderProjectCard(project))}
