import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { LearningTrack, Subcategory } from '../types';

interface SidebarProps {
  currentView: string;
  onViewChange: (view: any) => void;
  tracks: LearningTrack[];
  onTracksReorder: (tracks: LearningTrack[]) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, onViewChange, tracks, onTracksReorder }) => {
  const [draggedTrackIndex, setDraggedTrackIndex] = useState<number | null>(null);
  const [draggedSubIndex, setDraggedSubIndex] = useState<{ trackIdx: number, subIdx: number } | null>(null);
  const [expandedTrackIds, setExpandedTrackIds] = useState<Set<string>>(new Set(tracks.map(t => t.id)));

  // Inline adding state
  const [addingTrack, setAddingTrack] = useState(false);
  const [newTrackName, setNewTrackName] = useState('');
  const [addingSubToTrackId, setAddingSubToTrackId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if ((addingTrack || addingSubToTrackId) && inputRef.current) {
      inputRef.current.focus();
    }
  }, [addingTrack, addingSubToTrackId]);

  const toggleTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newExpanded = new Set(expandedTrackIds);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedTrackIds(newExpanded);
  };

  const submitNewTrack = () => {
    if (!newTrackName.trim()) {
      setAddingTrack(false);
      return;
    }

    const newTrack: LearningTrack = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTrackName.toUpperCase(),
      subtitle: `VIDEO TUTORIALS FOR ${newTrackName.toUpperCase()}`,
      icon: '📚',
      subcategories: []
    };

    onTracksReorder([...tracks, newTrack]);
    setExpandedTrackIds(prev => new Set(prev).add(newTrack.id));
    setNewTrackName('');
    setAddingTrack(false);
  };

  const submitNewSubcategory = (trackId: string) => {
    if (!newSubName.trim()) {
      setAddingSubToTrackId(null);
      return;
    }

    const newTracks = tracks.map(track => {
      if (track.id === trackId) {
        const subs = track.subcategories || [];
        return {
          ...track,
          subcategories: [...subs, { id: Math.random().toString(36).substr(2, 9), title: newSubName }]
        };
      }
      return track;
    });

    onTracksReorder(newTracks);
    setNewSubName('');
    setAddingSubToTrackId(null);
  };

  const handleDeleteTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm("Delete this track and all its contents?")) {
      onTracksReorder(tracks.filter(t => t.id !== id));
    }
  };

  const handleDeleteSub = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    const newTracks = tracks.map(t => {
      if (t.id === trackId) {
        return { ...t, subcategories: t.subcategories?.filter(s => s.id !== subId) };
      }
      return t;
    });
    onTracksReorder(newTracks);
  };

  // Drag & Drop logic
  const onTrackDragStart = (e: React.DragEvent, index: number) => {
    setDraggedTrackIndex(index);
    setDraggedSubIndex(null);
  };

  const onTrackDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedTrackIndex === null || draggedTrackIndex === index) return;
    const newTracks = [...tracks];
    const [item] = newTracks.splice(draggedTrackIndex, 1);
    newTracks.splice(index, 0, item);
    setDraggedTrackIndex(index);
    onTracksReorder(newTracks);
  };

  const onSubDragStart = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.stopPropagation();
    setDraggedSubIndex({ trackIdx, subIdx });
    setDraggedTrackIndex(null);
  };

  const onSubDragOver = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.preventDefault();
    e.stopPropagation();
    if (!draggedSubIndex || draggedSubIndex.trackIdx !== trackIdx || draggedSubIndex.subIdx === subIdx) return;

    const newTracks = JSON.parse(JSON.stringify(tracks)) as LearningTrack[];
    const track = newTracks[trackIdx];
    if (!track.subcategories) return;

    const [item] = track.subcategories.splice(draggedSubIndex.subIdx, 1);
    track.subcategories.splice(subIdx, 0, item);

    setDraggedSubIndex({ trackIdx, subIdx });
    onTracksReorder(newTracks);
  };

  return (
    <div className="w-80 h-screen bg-white border-r border-slate-200 flex flex-col py-8 px-4 relative shadow-sm shrink-0">
      <div className="flex items-center gap-3 px-2 mb-10 overflow-hidden whitespace-nowrap">
        <div className="w-10 h-10 shrink-0 bg-purple-700 rounded-xl flex items-center justify-center text-white shadow-lg shadow-purple-200">
          <div className="w-5 h-5 border-2 border-white rounded-lg flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>
        <div>
          <h2 className="text-sm font-black text-slate-900 leading-none tracking-tight">LEARNING</h2>
          <p className="text-[11px] font-bold text-purple-700 tracking-widest mt-0.5">GALLERY</p>
        </div>
      </div>

      <div className="space-y-1">
        <button
          onClick={() => onViewChange('home')}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all overflow-hidden whitespace-nowrap ${
            currentView === 'home' 
            ? 'bg-purple-700 text-white shadow-lg shadow-purple-200' 
            : 'text-slate-700 hover:bg-slate-100'
          }`}
        >
          {ICONS.Home}
          <span>HOME PAGE</span>
        </button>
      </div>

      <div className="mt-10 flex-1 overflow-y-auto no-scrollbar">
        <div className="px-4 flex items-center justify-between mb-6">
          <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest">LEARNING TRACKS</h3>
          <button 
            onClick={() => setAddingTrack(true)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-purple-700 transition-colors"
          >
            {ICONS.Plus}
          </button>
        </div>

        {addingTrack && (
          <div className="px-4 mb-4">
            <input
              ref={inputRef}
              value={newTrackName}
              onChange={(e) => setNewTrackName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && submitNewTrack()}
              onBlur={submitNewTrack}
              placeholder="New Track Name..."
              className="w-full px-3 py-2 text-xs font-bold uppercase tracking-widest border-2 border-purple-300 rounded-lg focus:outline-none focus:border-purple-600 bg-white text-slate-950 shadow-sm"
            />
          </div>
        )}

        <div className="space-y-2">
          {tracks.map((track, tIdx) => (
            <div key={track.id} className="space-y-1">
              <div
                draggable
                onDragStart={(e) => onTrackDragStart(e, tIdx)}
                onDragOver={(e) => onTrackDragOver(e, tIdx)}
                onDragEnd={() => setDraggedTrackIndex(null)}
                onClick={(e) => toggleTrack(e, track.id)}
                className={`group flex items-center gap-3 px-4 py-3.5 rounded-xl cursor-grab active:cursor-grabbing transition-all border border-transparent hover:bg-slate-50 hover:border-slate-200 ${
                  draggedTrackIndex === tIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'
                }`}
              >
                <span className="text-xl shrink-0">{track.icon}</span>
                <span className="flex-1 text-[12px] font-bold text-slate-900 tracking-wide uppercase truncate">
                  {track.title}
                </span>
                <button 
                  onClick={(e) => handleDeleteTrack(e, track.id)}
                  className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all"
                >
                  {ICONS.Delete}
                </button>
                <div className={`text-slate-400 transition-transform duration-300 ${expandedTrackIds.has(track.id) ? 'rotate-180' : ''}`}>
                  {ICONS.ChevronDown}
                </div>
              </div>

              {expandedTrackIds.has(track.id) && (
                <div className="ml-10 space-y-1 animate-in slide-in-from-top-2 duration-200">
                  {track.subcategories?.map((sub, sIdx) => (
                    <div
                      key={sub.id}
                      draggable
                      onDragStart={(e) => onSubDragStart(e, tIdx, sIdx)}
                      onDragOver={(e) => onSubDragOver(e, tIdx, sIdx)}
                      onDragEnd={() => setDraggedSubIndex(null)}
                      className={`group flex items-center gap-3 px-4 py-2.5 rounded-lg cursor-grab active:cursor-grabbing transition-all border border-transparent hover:bg-slate-50 hover:border-slate-200 ${
                        draggedSubIndex?.trackIdx === tIdx && draggedSubIndex?.subIdx === sIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'
                      }`}
                    >
                      <div className="w-1.5 h-1.5 rounded-full bg-slate-300 group-hover:bg-purple-500 transition-colors" />
                      <span className="flex-1 text-[11px] font-bold text-slate-600 tracking-wide uppercase truncate group-hover:text-slate-900">
                        {sub.title}
                      </span>
                      <button 
                        onClick={(e) => handleDeleteSub(e, track.id, sub.id)}
                        className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all scale-75"
                      >
                        {ICONS.Delete}
                      </button>
                    </div>
                  ))}

                  {addingSubToTrackId === track.id ? (
                    <div className="px-4 py-2">
                      <input
                        ref={inputRef}
                        value={newSubName}
                        onChange={(e) => setNewSubName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && submitNewSubcategory(track.id)}
                        onBlur={() => submitNewSubcategory(track.id)}
                        placeholder="Subcategory..."
                        className="w-full px-2 py-1 text-[10px] font-bold uppercase tracking-widest border border-purple-300 rounded focus:outline-none bg-white text-slate-950 shadow-sm"
                      />
                    </div>
                  ) : (
                    <button
                      onClick={(e) => { e.stopPropagation(); setAddingSubToTrackId(track.id); }}
                      className="w-full flex items-center gap-3 px-4 py-2 text-[10px] font-black text-purple-600/60 uppercase tracking-widest hover:text-purple-700 hover:bg-purple-50 rounded-lg transition-all"
                    >
                      <span className="scale-75">{ICONS.Plus}</span>
                      ADD SUBCATEGORY
                    </button>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <button className="mt-auto mx-2 flex items-center justify-center gap-2 py-3.5 px-4 rounded-xl bg-slate-900 text-white text-[11px] font-bold uppercase tracking-widest hover:bg-purple-800 transition-all shadow-md">
        {ICONS.Admin}
        ADMIN LOGIN
      </button>
    </div>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { Project, Section, ContentBlock, BlockType, LearningTrack, ProjectStatus, SectionStyle } from '../types';
import { ICONS } from '../constants';
import VideoPlayer from './VideoPlayer';

interface ProjectEditorProps {
  project: Project;
  onSave: (updated: Project) => void;
  onBack: () => void;
  tracks: LearningTrack[];
}

const GRID_COLUMNS = 12;

const ProjectEditor: React.FC<ProjectEditorProps> = ({ project, onSave, onBack, tracks }) => {
  const [sections, setSections] = useState<Section[]>(project.sections);
  const [title, setTitle] = useState(project.title);
  const [thumbnail, setThumbnail] = useState(project.thumbnail);
  const [trackId, setTrackId] = useState(project.trackId);
  const [subcategoryId, setSubcategoryId] = useState(project.subcategoryId || '');
  const [showThemeMenu, setShowThemeMenu] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeUpload, setActiveUpload] = useState<{ sId: string, bId: string, type: BlockType } | null>(null);

  const [resizing, setResizing] = useState<{ sId: string, bId: string, startX: number, startSpan: number } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [draggingBlock, setDraggingBlock] = useState<{ sId: string, bId: string } | null>(null);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!resizing || !containerRef.current) return;
      const containerWidth = containerRef.current.offsetWidth;
      const colWidth = containerWidth / GRID_COLUMNS;
      const deltaX = e.clientX - resizing.startX;
      const deltaSpan = Math.round(deltaX / colWidth);
      const newSpan = Math.min(GRID_COLUMNS, Math.max(1, resizing.startSpan + deltaSpan));
      updateBlock(resizing.sId, resizing.bId, { gridSpan: newSpan });
    };

    const handleMouseUp = () => setResizing(null);

    if (resizing) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [resizing]);

  const addSection = (cols: number = 1) => {
    const defaultSpan = Math.floor(GRID_COLUMNS / cols);
    const newSection: Section = {
      id: Math.random().toString(36).substr(2, 9),
      columns: cols,
      style: { background: 'white', padding: 'normal' },
      blocks: Array.from({ length: cols }).map(() => ({
        id: Math.random().toString(36).substr(2, 9),
        type: 'text',
        content: '',
        gridSpan: defaultSpan
      }))
    };
    setSections([...sections, newSection]);
  };

  const moveSection = (index: number, direction: 'up' | 'down') => {
    const newSections = [...sections];
    if (direction === 'up' && index > 0) {
      [newSections[index - 1], newSections[index]] = [newSections[index], newSections[index - 1]];
    } else if (direction === 'down' && index < newSections.length - 1) {
      [newSections[index + 1], newSections[index]] = [newSections[index], newSections[index + 1]];
    }
    setSections(newSections);
  };

  const updateSectionStyle = (sId: string, style: Partial<SectionStyle>) => {
    setSections(prev => prev.map(s => s.id === sId ? { ...s, style: { ...s.style!, ...style } } : s));
  };

  const handleBlockDragStart = (sId: string, bId: string) => {
    setDraggingBlock({ sId, bId });
  };

  const handleBlockDrop = (targetSId: string, targetIndex: number) => {
    if (!draggingBlock) return;
    const { sId: sourceSId, bId: sourceBId } = draggingBlock;
    const newSections = [...sections];
    const sourceSection = newSections.find(s => s.id === sourceSId);
    if (!sourceSection) return;
    const blockIndex = sourceSection.blocks.findIndex(b => b.id === sourceBId);
    const [movedBlock] = sourceSection.blocks.splice(blockIndex, 1);
    const targetSection = newSections.find(s => s.id === targetSId);
    if (targetSection) targetSection.blocks.splice(targetIndex, 0, movedBlock);
    setSections(newSections);
    setDraggingBlock(null);
  };

  const updateBlock = (sectionId: string, blockId: string, updates: Partial<ContentBlock>) => {
    setSections(prev => prev.map(s => {
      if (s.id !== sectionId) return s;
      return { ...s, blocks: s.blocks.map(b => (b.id === blockId ? { ...b, ...updates } : b)) };
    }));
  };

  const removeBlock = (sId: string, bId: string) => {
    setSections(prev => prev.map(s => {
      if (s.id !== sId) return s;
      return { ...s, blocks: s.blocks.filter(b => b.id !== bId) };
    }));
  };

  const addBlockToSection = (sId: string, type: BlockType) => {
    const newBlock: ContentBlock = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      content: '',
      gridSpan: 6
    };
    setSections(prev => prev.map(s => s.id === sId ? { ...s, blocks: [...s.blocks, newBlock] } : s));
  };

  const handleSave = () => {
    onSave({ 
      ...project, 
      title, 
      trackId, 
      subcategoryId: subcategoryId || undefined,
      sections, 
      thumbnail, 
      status: ProjectStatus.PUBLISHED, 
      lastEdited: 'Just now' 
    });
  };

  const getSectionBg = (bg?: string) => {
    switch(bg) {
      case 'gray': return 'bg-slate-100';
      case 'purple': return 'bg-purple-50';
      case 'dark': return 'bg-slate-900 text-white';
      default: return 'bg-white';
    }
  };

  const currentTrack = tracks.find(t => t.id === trackId);

  return (
    <div className="flex h-screen bg-slate-200/50">
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file && activeUpload) {
          const reader = new FileReader();
          reader.onload = (ev) => updateBlock(activeUpload.sId, activeUpload.bId, { content: ev.target?.result as string });
          reader.readAsDataURL(file);
        }
      }} />

      {/* Sidebar - Improved contrast */}
      <aside className="w-80 bg-white border-r border-slate-300 flex flex-col p-8 z-40 shadow-xl overflow-y-auto no-scrollbar">
        {/* Organization Selection */}
        <div className="mb-10">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-[12px] font-black text-slate-900 uppercase tracking-[0.2em]">Placement</h3>
          </div>
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Track</label>
              <select 
                value={trackId}
                onChange={(e) => {
                  setTrackId(e.target.value);
                  setSubcategoryId('');
                }}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-200 rounded-2xl text-[12px] font-bold text-slate-900 focus:outline-none focus:border-purple-600 appearance-none"
              >
                {tracks.map(t => (
                  <option key={t.id} value={t.id}>{t.title}</option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subcategory</label>
              <select 
                value={subcategoryId}
                onChange={(e) => setSubcategoryId(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-200 rounded-2xl text-[12px] font-bold text-slate-900 focus:outline-none focus:border-purple-600 appearance-none"
              >
                <option value="">No Subcategory</option>
                {currentTrack?.subcategories?.map(s => (
                  <option key={s.id} value={s.id}>{s.title}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        <div className="mb-10 pt-8 border-t-2 border-slate-100">
           <div className="flex items-center justify-between mb-8">
             <h3 className="text-[12px] font-black text-slate-900 uppercase tracking-[0.2em]">Build Canvas</h3>
             <span className="px-2 py-0.5 bg-purple-100 text-purple-700 rounded text-[9px] font-bold">GRID ACTIVE</span>
           </div>
           <div className="grid grid-cols-2 gap-4">
             {[
               { type: 'text', icon: ICONS.Text, label: 'Text' },
               { type: 'heading', icon: ICONS.Heading, label: 'Heading' },
               { type: 'image', icon: ICONS.Image, label: 'Image' },
               { type: 'video', icon: ICONS.Video, label: 'Video' },
               { type: 'divider', icon: ICONS.Divider, label: 'Divider' },
               { type: 'spacer', icon: ICONS.Resize, label: 'Space' },
             ].map(item => (
               <button 
                key={item.label}
                onClick={() => {
                  if (sections.length === 0) addSection();
                  else addBlockToSection(sections[sections.length - 1].id, item.type as BlockType);
                }}
                className="flex flex-col items-center justify-center p-5 bg-white border-2 border-slate-200 rounded-3xl hover:border-purple-600 hover:shadow-lg hover:shadow-purple-500/10 transition-all group active:scale-95"
               >
                 <span className="mb-2 text-slate-500 group-hover:text-purple-600 transition-transform group-hover:scale-110">{item.icon}</span>
                 <span className="text-[11px] font-black uppercase tracking-widest text-slate-700 group-hover:text-slate-950">{item.label}</span>
               </button>
             ))}
           </div>
        </div>

        <div className="mt-auto pt-8 border-t-2 border-slate-100">
           <button 
            onClick={() => addSection(1)}
            className="w-full flex items-center justify-center gap-3 py-5 bg-slate-950 text-white rounded-[2rem] text-[12px] font-black uppercase tracking-[0.2em] hover:bg-purple-700 transition-all shadow-xl active:scale-95"
           >
             {ICONS.Plus} ADD SECTION
           </button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-20 bg-white border-b-2 border-slate-300 px-10 flex items-center justify-between z-30">
          <div className="flex items-center gap-6">
            <button onClick={onBack} className="p-3 bg-slate-100 hover:bg-slate-200 rounded-2xl transition-all text-slate-900 border border-slate-300">{ICONS.Back}</button>
            <div className="flex flex-col">
              <input 
                value={title} 
                onChange={e => setTitle(e.target.value)} 
                className="text-xl font-black uppercase tracking-tight focus:outline-none bg-transparent w-96 text-slate-950 placeholder:text-slate-400"
                placeholder="UNTITLED PROJECT"
              />
              <div className="flex items-center gap-2 mt-0.5">
                <span className="w-2 h-2 bg-emerald-500 rounded-full shadow-[0_0_8px_rgba(16,185,129,0.5)]"></span>
                <span className="text-[11px] font-black text-slate-600 tracking-widest uppercase">Live Editing Active</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-6">
            <button onClick={handleSave} className="bg-purple-700 text-white px-10 py-3.5 rounded-full text-xs font-black uppercase tracking-widest hover:bg-slate-950 transition-all shadow-2xl">
              Publish Tutorial
            </button>
          </div>
        </header>

        {/* Stage */}
        <main className="flex-1 overflow-y-auto p-12 editor-canvas no-scrollbar">
          <div className="mx-auto max-w-6xl">
            <div className="min-h-[90vh] bg-white rounded-[4rem] shadow-2xl border-2 border-slate-300 overflow-hidden relative" ref={containerRef}>

              {sections.length === 0 && (
                <div className="h-[70vh] flex flex-col items-center justify-center text-center p-10 animate-slide-up">
                   <div className="w-24 h-24 bg-slate-100 border-2 border-slate-200 rounded-[3rem] flex items-center justify-center text-slate-400 mb-8">{ICONS.Plus}</div>
                   <h2 className="text-3xl font-black text-slate-950 uppercase tracking-tight mb-4">Your Canvas</h2>
                   <p className="text-slate-600 text-[14px] max-w-xs uppercase tracking-[0.2em] font-black leading-relaxed">Select a component to begin building.</p>
                </div>
              )}

              {sections.map((section, sIdx) => (
                <section 
                  key={section.id} 
                  className={`group relative border-b-2 border-slate-200 last:border-0 transition-all ${getSectionBg(section.style?.background)} ${section.style?.padding === 'compact' ? 'py-14' : section.style?.padding === 'large' ? 'py-44' : 'py-28'}`}
                  onDragOver={e => e.preventDefault()}
                  onDrop={() => handleBlockDrop(section.id, section.blocks.length)}
                >
                  {/* Grid Snap Overlay */}
                  {(resizing || draggingBlock) && (
                    <div className="absolute inset-0 z-0 pointer-events-none px-12 md:px-20 grid grid-cols-12 gap-10 opacity-5">
                      {Array.from({ length: 12 }).map((_, i) => (
                        <div key={i} className="h-full border-x border-slate-950" />
                      ))}
                    </div>
                  )}

                  {/* Section Controls */}
                  <div className="absolute left-6 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 flex flex-col gap-3 z-30 transition-all duration-300 translate-x-[-10px] group-hover:translate-x-0">
                    <button onClick={() => setShowThemeMenu(showThemeMenu === section.id ? null : section.id)} className="p-4 bg-slate-950 text-white rounded-[2rem] shadow-2xl hover:bg-purple-700 transition-all border border-slate-800">
                      {ICONS.Theme}
                    </button>
                    <div className="flex flex-col bg-slate-950 text-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-800">
                      <button onClick={() => moveSection(sIdx, 'up')} className="p-4 hover:bg-purple-700 transition-colors border-b border-slate-800">
                        <div className="rotate-[-90deg] scale-110">{ICONS.ChevronRight}</div>
                      </button>
                      <button onClick={() => moveSection(sIdx, 'down')} className="p-4 hover:bg-purple-700 transition-colors">
                        <div className="rotate-[90deg] scale-110">{ICONS.ChevronRight}</div>
                      </button>
                    </div>
                    <button onClick={() => setSections(sections.filter(s => s.id !== section.id))} className="p-4 bg-red-600 text-white rounded-[2rem] shadow-2xl hover:bg-red-700 transition-all">
                      {ICONS.Delete}
                    </button>
                  </div>

                  {/* Theme Overlay */}
                  {showThemeMenu === section.id && (
                    <div className="absolute left-28 top-1/2 -translate-y-1/2 w-64 bg-slate-950 rounded-[3rem] shadow-2xl border border-slate-800 p-8 z-50 animate-slide-up">
                      <p className="text-[12px] font-black text-white uppercase tracking-widest mb-6 border-b border-slate-800 pb-2">Appearance</p>
                      <div className="grid grid-cols-2 gap-4 mb-8">
                        {['white', 'gray', 'purple', 'dark'].map(bg => (
                          <button 
                            key={bg} 
                            onClick={() => updateSectionStyle(section.id, { background: bg as any })}
                            className={`h-12 rounded-2xl border-4 transition-all ${section.style?.background === bg ? 'border-purple-500 scale-110' : 'border-transparent'} ${bg === 'dark' ? 'bg-slate-800' : bg === 'purple' ? 'bg-purple-200' : bg === 'gray' ? 'bg-slate-200' : 'bg-white'}`}
                          />
                        ))}
                      </div>
                      <p className="text-[12px] font-black text-white uppercase tracking-widest mb-6 border-b border-slate-800 pb-2">Padding</p>
                      <div className="flex flex-col gap-2">
                        {['compact', 'normal', 'large'].map(p => (
                          <button 
                            key={p} 
                            onClick={() => updateSectionStyle(section.id, { padding: p as any })}
                            className={`w-full py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all ${section.style?.padding === p ? 'bg-white text-slate-950 shadow-xl' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
                          >
                            {p}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className="relative z-10 px-16 md:px-24 grid grid-cols-12 gap-12 md:gap-16 min-h-[120px]">
                    {section.blocks.map((block, bIdx) => {
                      const span = block.gridSpan || 12;
                      const isResizingThis = resizing?.bId === block.id;

                      return (
                        <div 
                          key={block.id} 
                          draggable 
                          onDragStart={() => handleBlockDragStart(section.id, block.id)}
                          onDragOver={e => e.preventDefault()}
                          onDrop={e => { e.stopPropagation(); handleBlockDrop(section.id, bIdx); }}
                          className={`relative group/block col-span-12 md:col-span-${Math.round(span)} flex flex-col p-8 rounded-[3.5rem] border-2 border-transparent transition-all duration-300 ${isResizingThis ? 'border-purple-600 bg-purple-50/50 shadow-inner' : 'hover:bg-slate-100/60 hover:border-slate-300'} ${draggingBlock?.bId === block.id ? 'opacity-20 scale-95' : 'opacity-100'}`}
                        >
                          {/* Block Tool Handle */}
                          <div className="absolute -top-6 left-1/2 -translate-x-1/2 flex items-center gap-2 opacity-0 group-hover/block:opacity-100 transition-all z-20">
                            <div className="p-3 bg-slate-950 text-white rounded-full shadow-2xl cursor-grab active:cursor-grabbing hover:bg-purple-700">
                              {ICONS.Grip}
                            </div>
                            <button 
                              onClick={() => removeBlock(section.id, block.id)}
                              className="p-3 bg-red-600 text-white rounded-full shadow-2xl hover:bg-red-700"
                            >
                              {ICONS.Delete}
                            </button>
                          </div>

                          {/* Resize Handle */}
                          <div 
                            onMouseDown={(e) => setResizing({ sId: section.id, bId: block.id, startX: e.clientX, startSpan: block.gridSpan || 12 })}
                            className="absolute right-0 top-1/2 -translate-y-1/2 w-8 h-16 cursor-ew-resize opacity-0 group-hover/block:opacity-100 transition-opacity z-20 flex items-center justify-center"
                          >
                             <div className="w-2 h-12 bg-slate-950 rounded-full shadow-xl" />
                          </div>

                          {/* Resize Badge */}
                          {isResizingThis && (
                            <div className="absolute -bottom-16 left-1/2 -translate-x-1/2 bg-slate-950 text-white text-[12px] font-black px-6 py-3 rounded-full z-50 whitespace-nowrap uppercase tracking-[0.25em] shadow-2xl border-2 border-purple-500/50">
                              Width: {block.gridSpan} Units
                            </div>
                          )}

                          <div className="flex-1">
                            {block.type === 'heading' ? (
                              <input 
                                value={block.content}
                                onChange={e => updateBlock(section.id, block.id, { content: e.target.value })}
                                placeholder="SECTION HEADING"
                                className="w-full bg-transparent text-4xl font-black uppercase tracking-tight focus:outline-none placeholder:text-slate-400 leading-none text-slate-950"
                              />
                            ) : block.type === 'text' ? (
                              <textarea 
                                value={block.content}
                                onChange={e => updateBlock(section.id, block.id, { content: e.target.value })}
                                placeholder="Describe the steps for this tutorial part..."
                                className="w-full bg-transparent min-h-[160px] text-xl font-bold leading-relaxed focus:outline-none resize-none placeholder:text-slate-500 text-slate-900"
                              />
                            ) : block.type === 'image' ? (
                              <div className="aspect-video w-full rounded-[3rem] overflow-hidden bg-slate-100 border-4 border-dashed border-slate-300 flex flex-col items-center justify-center gap-6 group/media transition-all hover:bg-slate-200/50 hover:border-purple-600">
                                {block.content ? (
                                  <img src={block.content} className="w-full h-full object-cover" alt="Content" />
                                ) : (
                                  <div className="text-center p-12">
                                    <div className="text-slate-400 mb-8 scale-[2.5]">{ICONS.Image}</div>
                                    <button onClick={() => { setActiveUpload({ sId: section.id, bId: block.id, type: 'image' }); fileInputRef.current?.click(); }} className="text-[13px] font-black uppercase text-purple-700 hover:text-purple-900 underline underline-offset-8 tracking-widest decoration-[3px]">Upload Asset</button>
                                  </div>
                                )}
                              </div>
                            ) : block.type === 'video' ? (
                              <div className="w-full">
                                {block.content ? (
                                  <VideoPlayer url={block.content} className="rounded-[3rem] shadow-2xl" />
                                ) : (
                                  <div className="aspect-video rounded-[3rem] bg-slate-950 flex flex-col items-center justify-center p-12 shadow-2xl transition-transform hover:scale-[1.02]">
                                    <div className="text-white/40 mb-10 scale-[2]">{ICONS.Video}</div>
                                    <input 
                                      placeholder="PASTE VIDEO LINK"
                                      className="w-full max-w-sm bg-white/10 border-2 border-white/20 rounded-[2rem] px-8 py-5 text-[12px] font-black text-white placeholder:text-white/30 focus:outline-none focus:ring-4 focus:ring-purple-600/50 uppercase tracking-[0.25em] text-center"
                                      onBlur={e => updateBlock(section.id, block.id, { content: e.target.value })}
                                    />
                                  </div>
                                )}
                              </div>
                            ) : block.type === 'divider' ? (
                              <div className="py-16"><div className="h-2 w-full bg-slate-200 rounded-full shadow-inner" /></div>
                            ) : (
                              <div className="h-40 flex items-center justify-center border-4 border-dashed border-slate-200 rounded-[3.5rem] text-[14px] text-slate-400 font-black uppercase tracking-[0.6em] bg-slate-100/50">Spacer Block</div>
                            )}
                          </div>
                        </div>
                      );
                    })}

                    {/* Add Placeholder */}
                    <button 
                      onClick={() => addBlockToSection(section.id, 'text')}
                      className="col-span-12 md:col-span-1 border-4 border-dashed border-slate-300 rounded-[3.5rem] flex items-center justify-center text-slate-400 hover:border-slate-950 hover:text-slate-950 hover:bg-slate-100 transition-all opacity-0 group-hover:opacity-100 min-h-[160px] group/add shadow-inner"
                    >
                      <div className="scale-150 transition-transform group-hover/add:rotate-90 group-hover/add:scale-[2]">{ICONS.Plus}</div>
                    </button>
                  </div>
                </section>
              ))}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default ProjectEditor;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ProjectEditor from './components/ProjectEditor';
import ProjectViewer from './components/ProjectViewer';
import { ICONS, DEFAULT_TRACKS } from './constants';
import { ViewState, Project, LearningTrack, ProjectStatus } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const handlePlayVideo = (p: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) window.open(videoUrl, '_blank');
    else handleProjectClick(p);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    return (
      <div 
        key={project.id}
        className="group bg-white rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-pointer hover:border-purple-400"
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div 
               onClick={(e) => handlePlayVideo(project, e)}
               className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500 cursor-pointer hover:bg-slate-50 active:scale-90"
             >
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-6 pt-6 border-t-2 border-slate-100">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <button 
               onClick={(e) => handlePlayVideo(project, e)}
               className="text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform hover:underline"
             >
               LEARN {ICONS.External}
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => (
    <div 
      key={`add-${trackId}-${subcategoryId || 'main'}`}
      onClick={() => handleCreateProject(trackId, subcategoryId)}
      className="group aspect-video xl:aspect-auto xl:h-full min-h-[250px] border-4 border-dashed border-slate-200 rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
    >
      <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
        <div className="scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
      </div>
      <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
        ADD TUTORIAL
      </span>
    </div>
  );

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
      />

      <main className="flex-1 flex flex-col relative overflow-y-auto px-12 py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div>
            <h1 className="text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter">
              LEARNING GALLERY
            </h1>
            <p className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>

          <div className="flex items-center gap-6">
            <div className="relative w-80">
              <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600">
                {ICONS.Search}
              </div>
              <input 
                type="text" 
                placeholder="Search tutorials..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-300 rounded-[2rem] text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
              />
            </div>
            <button 
              onClick={() => handleCreateProject()}
              className="flex items-center gap-3 bg-purple-700 text-white px-10 py-5 rounded-[2rem] text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
            >
              {ICONS.Plus} ADD TUTORIAL
            </button>
          </div>
        </header>

        <div className="space-y-32 pb-20">
          {tracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const hasSubcategories = track.subcategories && track.subcategories.length > 0;

            return (
              <section key={track.id} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                <div className="flex items-center justify-between border-b-4 border-slate-200 pb-8">
                  <div className="flex items-center gap-6">
                    <span className="text-5xl bg-white p-5 rounded-[2.5rem] shadow-xl border-2 border-slate-100">{track.icon}</span>
                    <div>
                      <h3 className="text-3xl font-black text-slate-950 uppercase tracking-tight leading-none">
                        {track.title}
                      </h3>
                      <p className="text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-3">
                        {track.subtitle}
                      </p>
                    </div>
                  </div>
                </div>

                {hasSubcategories ? (
                  <div className="space-y-16">
                    {track.subcategories?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-8 pl-4 border-l-4 border-purple-100">
                          <h4 className="text-xl font-black text-purple-700 uppercase tracking-widest flex items-center gap-4">
                            <span className="w-4 h-4 rounded-full bg-purple-600" />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {/* Projects in this track but without specific subcategory */}
                    {trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                    {trackProjects.map((project) => renderProjectCard(project))}
                    {renderAddPlaceholder(track.id)}
                  </div>
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ProjectEditor from './components/ProjectEditor';
import ProjectViewer from './components/ProjectViewer';
import { ICONS, DEFAULT_TRACKS } from './constants';
import { ViewState, Project, LearningTrack, ProjectStatus } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const handlePlayVideo = (p: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) window.open(videoUrl, '_blank');
    else handleProjectClick(p);
  };

  // Reordering logic
  const onProjectDragStart = (e: React.DragEvent, id: string) => {
    setDraggedProjectId(id);
    e.dataTransfer.setData('projectId', id);
  };

  const onProjectDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!draggedProjectId || draggedProjectId === targetId) return;

    const draggedIdx = projects.findIndex(p => p.id === draggedProjectId);
    const targetIdx = projects.findIndex(p => p.id === targetId);

    const draggedProj = projects[draggedIdx];
    const targetProj = projects[targetIdx];

    // Only allow swapping within the same track/subcategory context
    if (draggedProj.trackId !== targetProj.trackId || draggedProj.subcategoryId !== targetProj.subcategoryId) return;

    const newProjects = [...projects];
    const [movedProject] = newProjects.splice(draggedIdx, 1);
    newProjects.splice(targetIdx, 0, movedProject);

    setProjects(newProjects);
  };

  const onProjectDragEnd = () => {
    setDraggedProjectId(null);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    const isDragging = draggedProjectId === project.id;

    return (
      <div 
        key={project.id}
        draggable
        onDragStart={(e) => onProjectDragStart(e, project.id)}
        onDragOver={(e) => onProjectDragOver(e, project.id)}
        onDragEnd={onProjectDragEnd}
        className={`group bg-white rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-grab active:cursor-grabbing hover:border-purple-400 ${
          isDragging ? 'opacity-20 scale-95 border-purple-500' : 'opacity-100'
        }`}
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div 
               onClick={(e) => handlePlayVideo(project, e)}
               className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500 cursor-pointer hover:bg-slate-50 active:scale-90"
             >
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-6 pt-6 border-t-2 border-slate-100">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <button 
               onClick={(e) => handlePlayVideo(project, e)}
               className="text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform hover:underline"
             >
               LEARN {ICONS.External}
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => (
    <div 
      key={`add-${trackId}-${subcategoryId || 'main'}`}
      onClick={() => handleCreateProject(trackId, subcategoryId)}
      className="group aspect-video xl:aspect-auto xl:h-full min-h-[250px] border-4 border-dashed border-slate-200 rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
    >
      <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
        <div className="scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
      </div>
      <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
        ADD TUTORIAL
      </span>
    </div>
  );

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
      />

      <main className="flex-1 flex flex-col relative overflow-y-auto px-12 py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div>
            <h1 className="text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter">
              LEARNING GALLERY
            </h1>
            <p className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>

          <div className="flex items-center gap-6">
            <div className="relative w-80">
              <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600">
                {ICONS.Search}
              </div>
              <input 
                type="text" 
                placeholder="Search tutorials..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-300 rounded-[2rem] text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
              />
            </div>
            <button 
              onClick={() => handleCreateProject()}
              className="flex items-center gap-3 bg-purple-700 text-white px-10 py-5 rounded-[2rem] text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
            >
              {ICONS.Plus} ADD TUTORIAL
            </button>
          </div>
        </header>

        <div className="space-y-32 pb-20">
          {tracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const hasSubcategories = track.subcategories && track.subcategories.length > 0;

            return (
              <section key={track.id} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                <div className="flex items-center justify-between border-b-4 border-slate-200 pb-8">
                  <div className="flex items-center gap-6">
                    <span className="text-5xl bg-white p-5 rounded-[2.5rem] shadow-xl border-2 border-slate-100">{track.icon}</span>
                    <div>
                      <h3 className="text-3xl font-black text-slate-950 uppercase tracking-tight leading-none">
                        {track.title}
                      </h3>
                      <p className="text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-3">
                        {track.subtitle}
                      </p>
                    </div>
                  </div>
                </div>

                {hasSubcategories ? (
                  <div className="space-y-16">
                    {track.subcategories?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-8 pl-4 border-l-4 border-purple-100">
                          <h4 className="text-xl font-black text-purple-700 uppercase tracking-widest flex items-center gap-4">
                            <span className="w-4 h-4 rounded-full bg-purple-600" />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {/* Projects in this track but without specific subcategory */}
                    {trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                    {trackProjects.map((project) => renderProjectCard(project))}
                    {renderAddPlaceholder(track.id)}
                  </div>
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { LearningTrack, Subcategory } from '../types';

interface SidebarProps {
  currentView: string;
  onViewChange: (view: any) => void;
  tracks: LearningTrack[];
  onTracksReorder: (tracks: LearningTrack[]) => void;
  selectedTrackId: string | null;
  onTrackSelect: (id: string | null) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, onViewChange, tracks, onTracksReorder, selectedTrackId, onTrackSelect }) => {
  const [draggedTrackIndex, setDraggedTrackIndex] = useState<number | null>(null);
  const [draggedSubIndex, setDraggedSubIndex] = useState<{ trackIdx: number, subIdx: number } | null>(null);
  const [expandedTrackIds, setExpandedTrackIds] = useState<Set<string>>(new Set(tracks.map(t => t.id)));

  // Inline adding state
  const [addingTrack, setAddingTrack] = useState(false);
  const [newTrackName, setNewTrackName] = useState('');
  const [addingSubToTrackId, setAddingSubToTrackId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if ((addingTrack || addingSubToTrackId) && inputRef.current) {
      inputRef.current.focus();
    }
  }, [addingTrack, addingSubToTrackId]);

  const toggleTrackExpansion = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newExpanded = new Set(expandedTrackIds);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedTrackIds(newExpanded);
  };

  const handleTrackClick = (id: string) => {
    onTrackSelect(id);
    onViewChange('home');
    if (!expandedTrackIds.has(id)) {
      setExpandedTrackIds(prev => new Set(prev).add(id));
    }
  };

  const submitNewTrack = () => {
    if (!newTrackName.trim()) {
      setAddingTrack(false);
      return;
    }

    const newTrack: LearningTrack = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTrackName.toUpperCase(),
      subtitle: `VIDEO TUTORIALS FOR ${newTrackName.toUpperCase()}`,
      icon: '📚',
      subcategories: []
    };

    onTracksReorder([...tracks, newTrack]);
    setExpandedTrackIds(prev => new Set(prev).add(newTrack.id));
    setNewTrackName('');
    setAddingTrack(false);
  };

  const submitNewSubcategory = (trackId: string) => {
    if (!newSubName.trim()) {
      setAddingSubToTrackId(null);
      return;
    }

    const newTracks = tracks.map(track => {
      if (track.id === trackId) {
        const subs = track.subcategories || [];
        return {
          ...track,
          subcategories: [...subs, { id: Math.random().toString(36).substr(2, 9), title: newSubName }]
        };
      }
      return track;
    });

    onTracksReorder(newTracks);
    setNewSubName('');
    setAddingSubToTrackId(null);
  };

  const handleDeleteTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm("Delete this track and all its contents?")) {
      onTracksReorder(tracks.filter(t => t.id !== id));
      if (selectedTrackId === id) onTrackSelect(null);
    }
  };

  const handleDeleteSub = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    const newTracks = tracks.map(t => {
      if (t.id === trackId) {
        return { ...t, subcategories: t.subcategories?.filter(s => s.id !== subId) };
      }
      return t;
    });
    onTracksReorder(newTracks);
  };

  // Drag & Drop logic
  const onTrackDragStart = (e: React.DragEvent, index: number) => {
    setDraggedTrackIndex(index);
    setDraggedSubIndex(null);
  };

  const onTrackDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedTrackIndex === null || draggedTrackIndex === index) return;
    const newTracks = [...tracks];
    const [item] = newTracks.splice(draggedTrackIndex, 1);
    newTracks.splice(index, 0, item);
    setDraggedTrackIndex(index);
    onTracksReorder(newTracks);
  };

  const onSubDragStart = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.stopPropagation();
    setDraggedSubIndex({ trackIdx, subIdx });
    setDraggedTrackIndex(null);
  };

  const onSubDragOver = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.preventDefault();
    e.stopPropagation();
    if (!draggedSubIndex || draggedSubIndex.trackIdx !== trackIdx || draggedSubIndex.subIdx === subIdx) return;

    const newTracks = JSON.parse(JSON.stringify(tracks)) as LearningTrack[];
    const track = newTracks[trackIdx];
    if (!track.subcategories) return;

    const [item] = track.subcategories.splice(draggedSubIndex.subIdx, 1);
    track.subcategories.splice(subIdx, 0, item);

    setDraggedSubIndex({ trackIdx, subIdx });
    onTracksReorder(newTracks);
  };

  return (
    <div className="w-80 h-screen bg-white border-r border-slate-200 flex flex-col py-8 px-4 relative shadow-sm shrink-0">
      <div className="flex items-center gap-3 px-2 mb-10 overflow-hidden whitespace-nowrap">
        <div className="w-10 h-10 shrink-0 bg-purple-700 rounded-xl flex items-center justify-center text-white shadow-lg shadow-purple-200">
          <div className="w-5 h-5 border-2 border-white rounded-lg flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>
        <div>
          <h2 className="text-sm font-black text-slate-900 leading-none tracking-tight">LEARNING</h2>
          <p className="text-[11px] font-bold text-purple-700 tracking-widest mt-0.5">GALLERY</p>
        </div>
      </div>

      <div className="space-y-1">
        <button
          onClick={() => {
            onViewChange('home');
            onTrackSelect(null);
          }}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all overflow-hidden whitespace-nowrap ${
            currentView === 'home' && selectedTrackId === null
            ? 'bg-purple-700 text-white shadow-lg shadow-purple-200' 
            : 'text-slate-700 hover:bg-slate-100'
          }`}
        >
          {ICONS.Home}
          <span>HOME PAGE</span>
        </button>
      </div>

      <div className="mt-10 flex-1 overflow-y-auto no-scrollbar">
        <div className="px-4 flex items-center justify-between mb-6">
          <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest">LEARNING TRACKS</h3>
          <button 
            onClick={() => setAddingTrack(true)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-purple-700 transition-colors"
          >
            {ICONS.Plus}
          </button>
        </div>

        {addingTrack && (
          <div className="px-4 mb-4">
            <input
              ref={inputRef}
              value={newTrackName}
              onChange={(e) => setNewTrackName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && submitNewTrack()}
              onBlur={submitNewTrack}
              placeholder="New Track Name..."
              className="w-full px-3 py-2 text-xs font-bold uppercase tracking-widest border-2 border-purple-300 rounded-lg focus:outline-none focus:border-purple-600 bg-white text-slate-950 shadow-sm"
            />
          </div>
        )}

        <div className="space-y-2">
          {tracks.map((track, tIdx) => (
            <div key={track.id} className="space-y-1">
              <div
                draggable
                onDragStart={(e) => onTrackDragStart(e, tIdx)}
                onDragOver={(e) => onTrackDragOver(e, tIdx)}
                onDragEnd={() => setDraggedTrackIndex(null)}
                onClick={() => handleTrackClick(track.id)}
                className={`group flex items-center gap-3 px-4 py-3.5 rounded-xl cursor-grab active:cursor-grabbing transition-all border border-transparent ${
                  selectedTrackId === track.id 
                    ? 'bg-purple-100 border-purple-200 text-purple-900 shadow-sm' 
                    : 'hover:bg-slate-50 hover:border-slate-200 text-slate-900'
                } ${draggedTrackIndex === tIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'}`}
              >
                <span className="text-xl shrink-0">{track.icon}</span>
                <span className="flex-1 text-[12px] font-bold tracking-wide uppercase truncate">
                  {track.title}
                </span>
                <button 
                  onClick={(e) => handleDeleteTrack(e, track.id)}
                  className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all"
                >
                  {ICONS.Delete}
                </button>
                <div 
                  onClick={(e) => toggleTrackExpansion(e, track.id)}
                  className={`p-1 text-slate-400 hover:text-purple-600 transition-transform duration-300 ${expandedTrackIds.has(track.id) ? 'rotate-180' : ''}`}
                >
                  {ICONS.ChevronDown}
                </div>
              </div>

              {expandedTrackIds.has(track.id) && (
                <div className="ml-10 space-y-1 animate-in slide-in-from-top-2 duration-200">
                  {track.subcategories?.map((sub, sIdx) => (
                    <div
                      key={sub.id}
                      draggable
                      onDragStart={(e) => onSubDragStart(e, tIdx, sIdx)}
                      onDragOver={(e) => onSubDragOver(e, tIdx, sIdx)}
                      onDragEnd={() => setDraggedSubIndex(null)}
                      className={`group flex items-center gap-3 px-4 py-2.5 rounded-lg cursor-grab active:cursor-grabbing transition-all border border-transparent hover:bg-slate-50 hover:border-slate-200 ${
                        draggedSubIndex?.trackIdx === tIdx && draggedSubIndex?.subIdx === sIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'
                      }`}
                    >
                      <div className="w-1.5 h-1.5 rounded-full bg-slate-300 group-hover:bg-purple-500 transition-colors" />
                      <span className="flex-1 text-[11px] font-bold text-slate-600 tracking-wide uppercase truncate group-hover:text-slate-900">
                        {sub.title}
                      </span>
                      <button 
                        onClick={(e) => handleDeleteSub(e, track.id, sub.id)}
                        className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all scale-75"
                      >
                        {ICONS.Delete}
                      </button>
                    </div>
                  ))}

                  {addingSubToTrackId === track.id ? (
                    <div className="px-4 py-2">
                      <input
                        ref={inputRef}
                        value={newSubName}
                        onChange={(e) => setNewSubName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && submitNewSubcategory(track.id)}
                        onBlur={() => submitNewSubcategory(track.id)}
                        placeholder="Subcategory..."
                        className="w-full px-2 py-1 text-[10px] font-bold uppercase tracking-widest border border-purple-300 rounded focus:outline-none bg-white text-slate-950 shadow-sm"
                      />
                    </div>
                  ) : (
                    <button
                      onClick={(e) => { e.stopPropagation(); setAddingSubToTrackId(track.id); }}
                      className="w-full flex items-center gap-3 px-4 py-2 text-[10px] font-black text-purple-600/60 uppercase tracking-widest hover:text-purple-700 hover:bg-purple-50 rounded-lg transition-all"
                    >
                      <span className="scale-75">{ICONS.Plus}</span>
                      ADD SUBCATEGORY
                    </button>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <button className="mt-auto mx-2 flex items-center justify-center gap-2 py-3.5 px-4 rounded-xl bg-slate-900 text-white text-[11px] font-bold uppercase tracking-widest hover:bg-purple-800 transition-all shadow-md">
        {ICONS.Admin}
        ADMIN LOGIN
      </button>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ProjectEditor from './components/ProjectEditor';
import ProjectViewer from './components/ProjectViewer';
import { ICONS, DEFAULT_TRACKS } from './constants';
import { ViewState, Project, LearningTrack, ProjectStatus } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || selectedTrackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const handlePlayVideo = (p: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) window.open(videoUrl, '_blank');
    else handleProjectClick(p);
  };

  // Reordering logic
  const onProjectDragStart = (e: React.DragEvent, id: string) => {
    setDraggedProjectId(id);
    e.dataTransfer.setData('projectId', id);
  };

  const onProjectDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!draggedProjectId || draggedProjectId === targetId) return;

    const draggedIdx = projects.findIndex(p => p.id === draggedProjectId);
    const targetIdx = projects.findIndex(p => p.id === targetId);

    const draggedProj = projects[draggedIdx];
    const targetProj = projects[targetIdx];

    // Only allow swapping within the same track/subcategory context
    if (draggedProj.trackId !== targetProj.trackId || draggedProj.subcategoryId !== targetProj.subcategoryId) return;

    const newProjects = [...projects];
    const [movedProject] = newProjects.splice(draggedIdx, 1);
    newProjects.splice(targetIdx, 0, movedProject);

    setProjects(newProjects);
  };

  const onProjectDragEnd = () => {
    setDraggedProjectId(null);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    const isDragging = draggedProjectId === project.id;

    return (
      <div 
        key={project.id}
        draggable
        onDragStart={(e) => onProjectDragStart(e, project.id)}
        onDragOver={(e) => onProjectDragOver(e, project.id)}
        onDragEnd={onProjectDragEnd}
        className={`group bg-white rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-grab active:cursor-grabbing hover:border-purple-400 ${
          isDragging ? 'opacity-20 scale-95 border-purple-500' : 'opacity-100'
        }`}
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div 
               onClick={(e) => handlePlayVideo(project, e)}
               className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500 cursor-pointer hover:bg-slate-50 active:scale-90"
             >
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-6 pt-6 border-t-2 border-slate-100">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <button 
               onClick={(e) => handlePlayVideo(project, e)}
               className="text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform hover:underline"
             >
               LEARN {ICONS.External}
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => (
    <div 
      key={`add-${trackId}-${subcategoryId || 'main'}`}
      onClick={() => handleCreateProject(trackId, subcategoryId)}
      className="group aspect-video xl:aspect-auto xl:h-full min-h-[250px] border-4 border-dashed border-slate-200 rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
    >
      <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
        <div className="scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
      </div>
      <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
        ADD TUTORIAL
      </span>
    </div>
  );

  const visibleTracks = selectedTrackId 
    ? tracks.filter(t => t.id === selectedTrackId)
    : tracks;

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
        selectedTrackId={selectedTrackId}
        onTrackSelect={setSelectedTrackId}
      />

      <main className="flex-1 flex flex-col relative overflow-y-auto px-12 py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div onClick={() => setSelectedTrackId(null)} className="cursor-pointer group">
            <h1 className="text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter group-hover:text-purple-700 transition-colors">
              LEARNING GALLERY
            </h1>
            <p className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>

          <div className="flex items-center gap-6">
            {selectedTrackId && (
              <button 
                onClick={() => setSelectedTrackId(null)}
                className="text-[11px] font-black text-slate-500 hover:text-purple-700 uppercase tracking-widest flex items-center gap-2 transition-colors"
              >
                {ICONS.Back} ALL TRACKS
              </button>
            )}
            <div className="relative w-80">
              <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600">
                {ICONS.Search}
              </div>
              <input 
                type="text" 
                placeholder="Search tutorials..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-300 rounded-[2rem] text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
              />
            </div>
            <button 
              onClick={() => handleCreateProject()}
              className="flex items-center gap-3 bg-purple-700 text-white px-10 py-5 rounded-[2rem] text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
            >
              {ICONS.Plus} ADD TUTORIAL
            </button>
          </div>
        </header>

        <div className="space-y-32 pb-20">
          {visibleTracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const hasSubcategories = track.subcategories && track.subcategories.length > 0;

            return (
              <section key={track.id} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                <div 
                  className="flex items-center justify-between border-b-4 border-slate-200 pb-8 cursor-pointer group"
                  onClick={() => setSelectedTrackId(track.id)}
                >
                  <div className="flex items-center gap-6">
                    <span className="text-5xl bg-white p-5 rounded-[2.5rem] shadow-xl border-2 border-slate-100 group-hover:scale-105 transition-transform">{track.icon}</span>
                    <div>
                      <h3 className="text-3xl font-black text-slate-950 uppercase tracking-tight leading-none group-hover:text-purple-700 transition-colors">
                        {track.title}
                      </h3>
                      <p className="text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-3">
                        {track.subtitle}
                      </p>
                    </div>
                  </div>
                </div>

                {hasSubcategories ? (
                  <div className="space-y-16">
                    {track.subcategories?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-8 pl-4 border-l-4 border-purple-100">
                          <h4 className="text-xl font-black text-purple-700 uppercase tracking-widest flex items-center gap-4">
                            <span className="w-4 h-4 rounded-full bg-purple-600" />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {/* Projects in this track but without specific subcategory */}
                    {trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                    {trackProjects.map((project) => renderProjectCard(project))}
                    {renderAddPlaceholder(track.id)}
                  </div>
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ICONS } from '../constants';
import { LearningTrack, Subcategory } from '../types';

interface SidebarProps {
  currentView: string;
  onViewChange: (view: any) => void;
  tracks: LearningTrack[];
  onTracksReorder: (tracks: LearningTrack[]) => void;
  selectedTrackId: string | null;
  onTrackSelect: (id: string | null) => void;
  selectedSubcategoryId: string | null;
  onSubcategorySelect: (id: string | null) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  onViewChange, 
  tracks, 
  onTracksReorder, 
  selectedTrackId, 
  onTrackSelect,
  selectedSubcategoryId,
  onSubcategorySelect
}) => {
  const [draggedTrackIndex, setDraggedTrackIndex] = useState<number | null>(null);
  const [draggedSubIndex, setDraggedSubIndex] = useState<{ trackIdx: number, subIdx: number } | null>(null);
  const [expandedTrackIds, setExpandedTrackIds] = useState<Set<string>>(new Set(tracks.map(t => t.id)));

  // Inline adding state
  const [addingTrack, setAddingTrack] = useState(false);
  const [newTrackName, setNewTrackName] = useState('');
  const [addingSubToTrackId, setAddingSubToTrackId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if ((addingTrack || addingSubToTrackId) && inputRef.current) {
      inputRef.current.focus();
    }
  }, [addingTrack, addingSubToTrackId]);

  const toggleTrackExpansion = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newExpanded = new Set(expandedTrackIds);
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpandedTrackIds(newExpanded);
  };

  const handleTrackClick = (id: string) => {
    onTrackSelect(id);
    onSubcategorySelect(null);
    onViewChange('home');
    if (!expandedTrackIds.has(id)) {
      setExpandedTrackIds(prev => new Set(prev).add(id));
    }
  };

  const handleSubcategoryClick = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    onTrackSelect(trackId);
    onSubcategorySelect(subId);
    onViewChange('home');
  };

  const submitNewTrack = () => {
    if (!newTrackName.trim()) {
      setAddingTrack(false);
      return;
    }

    const newTrack: LearningTrack = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTrackName.toUpperCase(),
      subtitle: `VIDEO TUTORIALS FOR ${newTrackName.toUpperCase()}`,
      icon: '📚',
      subcategories: []
    };

    onTracksReorder([...tracks, newTrack]);
    setExpandedTrackIds(prev => new Set(prev).add(newTrack.id));
    setNewTrackName('');
    setAddingTrack(false);
  };

  const submitNewSubcategory = (trackId: string) => {
    if (!newSubName.trim()) {
      setAddingSubToTrackId(null);
      return;
    }

    const newTracks = tracks.map(track => {
      if (track.id === trackId) {
        const subs = track.subcategories || [];
        return {
          ...track,
          subcategories: [...subs, { id: Math.random().toString(36).substr(2, 9), title: newSubName }]
        };
      }
      return track;
    });

    onTracksReorder(newTracks);
    setNewSubName('');
    setAddingSubToTrackId(null);
  };

  const handleDeleteTrack = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm("Delete this track and all its contents?")) {
      onTracksReorder(tracks.filter(t => t.id !== id));
      if (selectedTrackId === id) {
        onTrackSelect(null);
        onSubcategorySelect(null);
      }
    }
  };

  const handleDeleteSub = (e: React.MouseEvent, trackId: string, subId: string) => {
    e.stopPropagation();
    const newTracks = tracks.map(t => {
      if (t.id === trackId) {
        return { ...t, subcategories: t.subcategories?.filter(s => s.id !== subId) };
      }
      return t;
    });
    onTracksReorder(newTracks);
    if (selectedSubcategoryId === subId) onSubcategorySelect(null);
  };

  // Drag & Drop logic
  const onTrackDragStart = (e: React.DragEvent, index: number) => {
    setDraggedTrackIndex(index);
    setDraggedSubIndex(null);
  };

  const onTrackDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedTrackIndex === null || draggedTrackIndex === index) return;
    const newTracks = [...tracks];
    const [item] = newTracks.splice(draggedTrackIndex, 1);
    newTracks.splice(index, 0, item);
    setDraggedTrackIndex(index);
    onTracksReorder(newTracks);
  };

  const onSubDragStart = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.stopPropagation();
    setDraggedSubIndex({ trackIdx, subIdx });
    setDraggedTrackIndex(null);
  };

  const onSubDragOver = (e: React.DragEvent, trackIdx: number, subIdx: number) => {
    e.preventDefault();
    e.stopPropagation();
    if (!draggedSubIndex || draggedSubIndex.trackIdx !== trackIdx || draggedSubIndex.subIdx === subIdx) return;

    const newTracks = JSON.parse(JSON.stringify(tracks)) as LearningTrack[];
    const track = newTracks[trackIdx];
    if (!track.subcategories) return;

    const [item] = track.subcategories.splice(draggedSubIndex.subIdx, 1);
    track.subcategories.splice(subIdx, 0, item);

    setDraggedSubIndex({ trackIdx, subIdx });
    onTracksReorder(newTracks);
  };

  return (
    <div className="w-80 h-screen bg-white border-r border-slate-200 flex flex-col py-8 px-4 relative shadow-sm shrink-0">
      <div className="flex items-center gap-3 px-2 mb-10 overflow-hidden whitespace-nowrap">
        <div className="w-10 h-10 shrink-0 bg-purple-700 rounded-xl flex items-center justify-center text-white shadow-lg shadow-purple-200">
          <div className="w-5 h-5 border-2 border-white rounded-lg flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>
        <div>
          <h2 className="text-sm font-black text-slate-900 leading-none tracking-tight">LEARNING</h2>
          <p className="text-[11px] font-bold text-purple-700 tracking-widest mt-0.5">GALLERY</p>
        </div>
      </div>

      <div className="space-y-1">
        <button
          onClick={() => {
            onViewChange('home');
            onTrackSelect(null);
            onSubcategorySelect(null);
          }}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-widest transition-all overflow-hidden whitespace-nowrap ${
            currentView === 'home' && selectedTrackId === null
            ? 'bg-purple-700 text-white shadow-lg shadow-purple-200' 
            : 'text-slate-700 hover:bg-slate-100'
          }`}
        >
          {ICONS.Home}
          <span>HOME PAGE</span>
        </button>
      </div>

      <div className="mt-10 flex-1 overflow-y-auto no-scrollbar">
        <div className="px-4 flex items-center justify-between mb-6">
          <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest">LEARNING TRACKS</h3>
          <button 
            onClick={() => setAddingTrack(true)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-purple-700 transition-colors"
          >
            {ICONS.Plus}
          </button>
        </div>

        {addingTrack && (
          <div className="px-4 mb-4">
            <input
              ref={inputRef}
              value={newTrackName}
              onChange={(e) => setNewTrackName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && submitNewTrack()}
              onBlur={submitNewTrack}
              placeholder="New Track Name..."
              className="w-full px-3 py-2 text-xs font-bold uppercase tracking-widest border-2 border-purple-300 rounded-lg focus:outline-none focus:border-purple-600 bg-white text-slate-950 shadow-sm"
            />
          </div>
        )}

        <div className="space-y-2">
          {tracks.map((track, tIdx) => (
            <div key={track.id} className="space-y-1">
              <div
                draggable
                onDragStart={(e) => onTrackDragStart(e, tIdx)}
                onDragOver={(e) => onTrackDragOver(e, tIdx)}
                onDragEnd={() => setDraggedTrackIndex(null)}
                onClick={() => handleTrackClick(track.id)}
                className={`group flex items-center gap-3 px-4 py-3.5 rounded-xl cursor-grab active:cursor-grabbing transition-all border border-transparent ${
                  selectedTrackId === track.id && selectedSubcategoryId === null
                    ? 'bg-purple-100 border-purple-200 text-purple-900 shadow-sm' 
                    : 'hover:bg-slate-50 hover:border-slate-200 text-slate-900'
                } ${draggedTrackIndex === tIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'}`}
              >
                <span className="text-xl shrink-0">{track.icon}</span>
                <span className="flex-1 text-[12px] font-bold tracking-wide uppercase truncate">
                  {track.title}
                </span>
                <button 
                  onClick={(e) => handleDeleteTrack(e, track.id)}
                  className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all"
                >
                  {ICONS.Delete}
                </button>
                <div 
                  onClick={(e) => toggleTrackExpansion(e, track.id)}
                  className={`p-1 text-slate-400 hover:text-purple-600 transition-transform duration-300 ${expandedTrackIds.has(track.id) ? 'rotate-180' : ''}`}
                >
                  {ICONS.ChevronDown}
                </div>
              </div>

              {expandedTrackIds.has(track.id) && (
                <div className="ml-10 space-y-1 animate-in slide-in-from-top-2 duration-200">
                  {track.subcategories?.map((sub, sIdx) => (
                    <div
                      key={sub.id}
                      draggable
                      onDragStart={(e) => onSubDragStart(e, tIdx, sIdx)}
                      onDragOver={(e) => onSubDragOver(e, tIdx, sIdx)}
                      onDragEnd={() => setDraggedSubIndex(null)}
                      onClick={(e) => handleSubcategoryClick(e, track.id, sub.id)}
                      className={`group flex items-center gap-3 px-4 py-2.5 rounded-lg cursor-grab active:cursor-grabbing transition-all border border-transparent ${
                        selectedSubcategoryId === sub.id 
                          ? 'bg-purple-50 border-purple-100 text-purple-700' 
                          : 'hover:bg-slate-50 hover:border-slate-200 text-slate-600'
                      } ${draggedSubIndex?.trackIdx === tIdx && draggedSubIndex?.subIdx === sIdx ? 'opacity-40 bg-purple-50 scale-95' : 'opacity-100'}`}
                    >
                      <div className={`w-1.5 h-1.5 rounded-full transition-colors ${selectedSubcategoryId === sub.id ? 'bg-purple-700' : 'bg-slate-300 group-hover:bg-purple-500'}`} />
                      <span className={`flex-1 text-[11px] font-bold tracking-wide uppercase truncate ${selectedSubcategoryId === sub.id ? 'text-purple-900' : 'group-hover:text-slate-900'}`}>
                        {sub.title}
                      </span>
                      <button 
                        onClick={(e) => handleDeleteSub(e, track.id, sub.id)}
                        className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-500 transition-all scale-75"
                      >
                        {ICONS.Delete}
                      </button>
                    </div>
                  ))}

                  {addingSubToTrackId === track.id ? (
                    <div className="px-4 py-2">
                      <input
                        ref={inputRef}
                        value={newSubName}
                        onChange={(e) => setNewSubName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && submitNewSubcategory(track.id)}
                        onBlur={() => submitNewSubcategory(track.id)}
                        placeholder="Subcategory..."
                        className="w-full px-2 py-1 text-[10px] font-bold uppercase tracking-widest border border-purple-300 rounded focus:outline-none bg-white text-slate-950 shadow-sm"
                      />
                    </div>
                  ) : (
                    <button
                      onClick={(e) => { e.stopPropagation(); setAddingSubToTrackId(track.id); }}
                      className="w-full flex items-center gap-3 px-4 py-2 text-[10px] font-black text-purple-600/60 uppercase tracking-widest hover:text-purple-700 hover:bg-purple-50 rounded-lg transition-all"
                    >
                      <span className="scale-75">{ICONS.Plus}</span>
                      ADD SUBCATEGORY
                    </button>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      <button className="mt-auto mx-2 flex items-center justify-center gap-2 py-3.5 px-4 rounded-xl bg-slate-900 text-white text-[11px] font-bold uppercase tracking-widest hover:bg-purple-800 transition-all shadow-md">
        {ICONS.Admin}
        ADMIN LOGIN
      </button>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ProjectEditor from './components/ProjectEditor';
import ProjectViewer from './components/ProjectViewer';
import { ICONS, DEFAULT_TRACKS } from './constants';
import { ViewState, Project, LearningTrack, ProjectStatus } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);
  const [selectedSubcategoryId, setSelectedSubcategoryId] = useState<string | null>(null);

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || selectedTrackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId || selectedSubcategoryId || undefined,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const handlePlayVideo = (p: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) window.open(videoUrl, '_blank');
    else handleProjectClick(p);
  };

  // Reordering logic
  const onProjectDragStart = (e: React.DragEvent, id: string) => {
    setDraggedProjectId(id);
    e.dataTransfer.setData('projectId', id);
  };

  const onProjectDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!draggedProjectId || draggedProjectId === targetId) return;

    const draggedIdx = projects.findIndex(p => p.id === draggedProjectId);
    const targetIdx = projects.findIndex(p => p.id === targetId);

    const draggedProj = projects[draggedIdx];
    const targetProj = projects[targetIdx];

    // Only allow swapping within the same track/subcategory context
    if (draggedProj.trackId !== targetProj.trackId || draggedProj.subcategoryId !== targetProj.subcategoryId) return;

    const newProjects = [...projects];
    const [movedProject] = newProjects.splice(draggedIdx, 1);
    newProjects.splice(targetIdx, 0, movedProject);

    setProjects(newProjects);
  };

  const onProjectDragEnd = () => {
    setDraggedProjectId(null);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    const isDragging = draggedProjectId === project.id;

    return (
      <div 
        key={project.id}
        draggable
        onDragStart={(e) => onProjectDragStart(e, project.id)}
        onDragOver={(e) => onProjectDragOver(e, project.id)}
        onDragEnd={onProjectDragEnd}
        className={`group bg-white rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-grab active:cursor-grabbing hover:border-purple-400 ${
          isDragging ? 'opacity-20 scale-95 border-purple-500' : 'opacity-100'
        }`}
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div 
               onClick={(e) => handlePlayVideo(project, e)}
               className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500 cursor-pointer hover:bg-slate-50 active:scale-90"
             >
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-6 pt-6 border-t-2 border-slate-100">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <button 
               onClick={(e) => handlePlayVideo(project, e)}
               className="text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform hover:underline"
             >
               LEARN {ICONS.External}
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => (
    <div 
      key={`add-${trackId}-${subcategoryId || 'main'}`}
      onClick={() => handleCreateProject(trackId, subcategoryId)}
      className="group aspect-video xl:aspect-auto xl:h-full min-h-[250px] border-4 border-dashed border-slate-200 rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
    >
      <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
        <div className="scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
      </div>
      <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
        ADD TUTORIAL
      </span>
    </div>
  );

  const visibleTracks = selectedTrackId 
    ? tracks.filter(t => t.id === selectedTrackId)
    : tracks;

  const getBreadcrumbs = () => {
    const crumbs = [];
    crumbs.push(
      <button 
        key="all" 
        onClick={() => { setSelectedTrackId(null); setSelectedSubcategoryId(null); }}
        className="hover:text-purple-700 transition-colors"
      >
        LEARNING GALLERY
      </button>
    );

    if (selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      crumbs.push(<span key="s1" className="text-slate-300 mx-2">/</span>);
      crumbs.push(
        <button 
          key="track" 
          onClick={() => setSelectedSubcategoryId(null)}
          className={`hover:text-purple-700 transition-colors ${!selectedSubcategoryId ? 'text-purple-700' : ''}`}
        >
          {track?.title}
        </button>
      );
    }

    if (selectedSubcategoryId && selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      const sub = track?.subcategories?.find(s => s.id === selectedSubcategoryId);
      crumbs.push(<span key="s2" className="text-slate-300 mx-2">/</span>);
      crumbs.push(<span key="sub" className="text-purple-700">{sub?.title}</span>);
    }

    return crumbs;
  };

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
        selectedTrackId={selectedTrackId}
        onTrackSelect={setSelectedTrackId}
        selectedSubcategoryId={selectedSubcategoryId}
        onSubcategorySelect={setSelectedSubcategoryId}
      />

      <main className="flex-1 flex flex-col relative overflow-y-auto px-12 py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div className="group">
            <h1 className="text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter flex items-center flex-wrap">
              {getBreadcrumbs()}
            </h1>
            <p className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>

          <div className="flex items-center gap-6">
            {(selectedTrackId || selectedSubcategoryId) && (
              <button 
                onClick={() => { 
                  if (selectedSubcategoryId) setSelectedSubcategoryId(null);
                  else setSelectedTrackId(null);
                }}
                className="text-[11px] font-black text-slate-500 hover:text-purple-700 uppercase tracking-widest flex items-center gap-2 transition-colors bg-white px-4 py-3 rounded-2xl border-2 border-slate-200 shadow-sm"
              >
                {ICONS.Back} GO BACK
              </button>
            )}
            <div className="relative w-80">
              <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600">
                {ICONS.Search}
              </div>
              <input 
                type="text" 
                placeholder="Search tutorials..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-300 rounded-[2rem] text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
              />
            </div>
            <button 
              onClick={() => handleCreateProject()}
              className="flex items-center gap-3 bg-purple-700 text-white px-10 py-5 rounded-[2rem] text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
            >
              {ICONS.Plus} ADD TUTORIAL
            </button>
          </div>
        </header>

        <div className="space-y-32 pb-20">
          {visibleTracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const subcategoriesToRender = selectedSubcategoryId 
              ? track.subcategories?.filter(s => s.id === selectedSubcategoryId) 
              : track.subcategories;

            const hasSubcategories = subcategoriesToRender && subcategoriesToRender.length > 0;

            return (
              <section key={track.id} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                {!selectedTrackId && (
                  <div 
                    className="flex items-center justify-between border-b-4 border-slate-200 pb-8 cursor-pointer group"
                    onClick={() => setSelectedTrackId(track.id)}
                  >
                    <div className="flex items-center gap-6">
                      <span className="text-5xl bg-white p-5 rounded-[2.5rem] shadow-xl border-2 border-slate-100 group-hover:scale-105 transition-transform">{track.icon}</span>
                      <div>
                        <h3 className="text-3xl font-black text-slate-950 uppercase tracking-tight leading-none group-hover:text-purple-700 transition-colors">
                          {track.title}
                        </h3>
                        <p className="text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-3">
                          {track.subtitle}
                        </p>
                      </div>
                    </div>
                  </div>
                )}

                {hasSubcategories ? (
                  <div className="space-y-16">
                    {subcategoriesToRender?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-8 pl-4 border-l-4 border-purple-100">
                          <h4 
                            className={`text-xl font-black uppercase tracking-widest flex items-center gap-4 cursor-pointer hover:text-purple-900 transition-colors ${selectedSubcategoryId === sub.id ? 'text-purple-900' : 'text-purple-700'}`}
                            onClick={() => setSelectedSubcategoryId(sub.id)}
                          >
                            <span className={`w-4 h-4 rounded-full ${selectedSubcategoryId === sub.id ? 'bg-purple-900 scale-125' : 'bg-purple-600'}`} />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {/* Projects in this track but without specific subcategory - only show if no specific subcategory is selected or if we're viewing all */}
                    {!selectedSubcategoryId && trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  // Only show direct projects if no specific subcategory is requested or if track has no subcategories
                  (!selectedSubcategoryId) && (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                      {trackProjects.map((project) => renderProjectCard(project))}
                      {renderAddPlaceholder(track.id)}
                    </div>
                  )
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Project, LearningTrack, ProjectStatus, Section, ContentBlock } from '../types';
import { ICONS } from '../constants';
import VideoPlayer from './VideoPlayer';

interface ProjectEditorProps {
  project: Project;
  onSave: (updated: Project) => void;
  onBack: () => void;
  tracks: LearningTrack[];
}

const ProjectEditor: React.FC<ProjectEditorProps> = ({ project, onSave, onBack, tracks }) => {
  const [title, setTitle] = useState(project.title);
  const [thumbnail, setThumbnail] = useState(project.thumbnail);
  const [trackId, setTrackId] = useState(project.trackId);
  const [subcategoryId, setSubcategoryId] = useState(project.subcategoryId || '');

  // Extract initial values from existing project structure if they exist
  const initialVideo = project.sections?.[0]?.blocks.find(b => b.type === 'video')?.content || '';
  const initialDesc = project.sections?.[0]?.blocks.find(b => b.type === 'text')?.content || '';

  const [videoLink, setVideoLink] = useState(initialVideo);
  const [description, setDescription] = useState(initialDesc);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = () => {
    // Construct the sections array to match the expected format for ProjectViewer
    const blocks: ContentBlock[] = [];

    if (videoLink) {
      blocks.push({
        id: 'main-video',
        type: 'video',
        content: videoLink,
        gridSpan: 12
      });
    }

    if (description) {
      blocks.push({
        id: 'main-desc',
        type: 'text',
        content: description,
        gridSpan: 12
      });
    }

    const simpleSection: Section = {
      id: 'main-section',
      columns: 1,
      style: { background: 'white', padding: 'normal' },
      blocks: blocks
    };

    onSave({ 
      ...project, 
      title, 
      trackId, 
      subcategoryId: subcategoryId || undefined,
      sections: [simpleSection], 
      thumbnail, 
      status: ProjectStatus.PUBLISHED, 
      lastEdited: 'Just now' 
    });
  };

  const currentTrack = tracks.find(t => t.id === trackId);

  return (
    <div className="flex flex-col h-screen bg-slate-50 overflow-hidden">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={(e) => {
          const file = e.target.files?.[0];
          if (file) {
            const reader = new FileReader();
            reader.onload = (ev) => setThumbnail(ev.target?.result as string);
            reader.readAsDataURL(file);
          }
        }} 
      />

      {/* Header */}
      <header className="h-20 bg-white border-b-2 border-slate-200 px-10 flex items-center justify-between z-30 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="p-3 bg-slate-100 hover:bg-slate-200 rounded-2xl transition-all text-slate-900 border border-slate-200">
            {ICONS.Back}
          </button>
          <h2 className="text-xl font-black uppercase tracking-tight text-slate-950">
            {project.id ? 'Edit Tutorial' : 'Create New Tutorial'}
          </h2>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={onBack} 
            className="px-8 py-3.5 rounded-full text-xs font-black uppercase tracking-widest text-slate-500 hover:bg-slate-100 transition-all"
          >
            Cancel
          </button>
          <button 
            onClick={handleSave} 
            className="bg-purple-700 text-white px-10 py-3.5 rounded-full text-xs font-black uppercase tracking-widest hover:bg-slate-950 transition-all shadow-xl"
          >
            Save & Publish
          </button>
        </div>
      </header>

      {/* Form Area */}
      <main className="flex-1 overflow-y-auto p-12 no-scrollbar">
        <div className="max-w-4xl mx-auto space-y-12 animate-slide-up pb-20">

          {/* Section: Basic Info */}
          <div className="bg-white rounded-[3rem] p-10 border-2 border-slate-200 shadow-sm space-y-8">
            <h3 className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em]">Basic Information</h3>

            <div className="space-y-2">
              <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Tutorial Title</label>
              <input 
                value={title} 
                onChange={e => setTitle(e.target.value)}
                placeholder="Enter a descriptive title..."
                className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[16px] font-bold text-slate-950 focus:outline-none focus:border-purple-600 transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Target Track</label>
                <select 
                  value={trackId}
                  onChange={(e) => {
                    setTrackId(e.target.value);
                    setSubcategoryId('');
                  }}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[14px] font-bold text-slate-950 focus:outline-none focus:border-purple-600 transition-all appearance-none"
                >
                  {tracks.map(t => (
                    <option key={t.id} value={t.id}>{t.title}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Subcategory</label>
                <select 
                  value={subcategoryId}
                  onChange={(e) => setSubcategoryId(e.target.value)}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-[14px] font-bold text-slate-950 focus:outline-none focus:border-purple-600 transition-all appearance-none"
                >
                  <option value="">No Subcategory</option>
                  {currentTrack?.subcategories?.map(s => (
