              ) : (
                <div className="text-center p-12">
                  <div className="text-slate-300 mb-6 scale-[2.5]">{ICONS.Image}</div>
                  <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.2em]">Upload a banner image</p>
                </div>
              )}
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

