        { id: 'main-desc', type: 'text', content: 'Master the basics of Python syntax. We will walk through setting up your development environment and writing a simple script that interacts with the user. Perfect for absolute beginners starting their coding journey.', gridSpan: 12 }
      ]
    }]
  }
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [tracks, setTracks] = useState<LearningTrack[]>(DEFAULT_TRACKS);
  const [projects, setProjects] = useState<Project[]>(DEMO_PROJECTS);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);
  const [selectedSubcategoryId, setSelectedSubcategoryId] = useState<string | null>(null);

  const getYoutubeThumbnail = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      let videoId = '';
      if (urlObj.hostname.includes('youtu.be')) {
        videoId = urlObj.pathname.slice(1);
      } else if (urlObj.hostname.includes('youtube.com')) {
        videoId = urlObj.searchParams.get('v') || '';
      }
      return videoId ? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg` : null;
    } catch (e) { return null; }
  };

  const getProjectDisplayThumbnail = (p: Project) => {
    const isDefault = p.thumbnail.includes('unsplash.com/photo-1498050108023-c5249f4df085');
    if (!isDefault && p.thumbnail) return p.thumbnail;
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) {
      const ytThumb = getYoutubeThumbnail(videoUrl);
      if (ytThumb) return ytThumb;
    }
    return p.thumbnail;
  };

  const handleCreateProject = (trackId?: string, subcategoryId?: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Tutorial Title',
      thumbnail: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?q=80&w=1000&auto=format&fit=crop',
      status: ProjectStatus.DRAFT,
      lastEdited: 'Just now',
      trackId: trackId || selectedTrackId || tracks[0]?.id || '',
      subcategoryId: subcategoryId || selectedSubcategoryId || undefined,
      sections: []
    };
    setSelectedProject(newProject);
    setCurrentView('editor');
  };

  const handleSaveProject = (updated: Project) => {
    setProjects(prev => {
      const exists = prev.find(p => p.id === updated.id);
      if (exists) return prev.map(p => (p.id === updated.id ? updated : p));
      return [updated, ...prev];
    });
    setCurrentView('home');
    setSelectedProject(null);
  };

  const handleProjectClick = (p: Project) => {
    setSelectedProject(p);
    setCurrentView('viewer');
  };

  const handlePlayVideo = (p: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    const videoUrl = p.sections
      .flatMap(section => section.blocks)
      .find(block => block.type === 'video' && block.content)?.content;
    if (videoUrl) window.open(videoUrl, '_blank');
    else handleProjectClick(p);
  };

  // Reordering logic
  const onProjectDragStart = (e: React.DragEvent, id: string) => {
    setDraggedProjectId(id);
    e.dataTransfer.setData('projectId', id);
  };

  const onProjectDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!draggedProjectId || draggedProjectId === targetId) return;

    const draggedIdx = projects.findIndex(p => p.id === draggedProjectId);
    const targetIdx = projects.findIndex(p => p.id === targetId);

    const draggedProj = projects[draggedIdx];
    const targetProj = projects[targetIdx];

    // Only allow swapping within the same track/subcategory context
    if (draggedProj.trackId !== targetProj.trackId || draggedProj.subcategoryId !== targetProj.subcategoryId) return;

    const newProjects = [...projects];
    const [movedProject] = newProjects.splice(draggedIdx, 1);
    newProjects.splice(targetIdx, 0, movedProject);

    setProjects(newProjects);
  };

  const onProjectDragEnd = () => {
    setDraggedProjectId(null);
  };

  const filteredProjects = projects.filter(p => 
    p.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const renderProjectCard = (project: Project) => {
    const displayImg = getProjectDisplayThumbnail(project);
    const isDragging = draggedProjectId === project.id;

    return (
      <div 
        key={project.id}
        draggable
        onDragStart={(e) => onProjectDragStart(e, project.id)}
        onDragOver={(e) => onProjectDragOver(e, project.id)}
        onDragEnd={onProjectDragEnd}
        className={`group bg-white rounded-[3.5rem] border-2 border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-purple-700/20 transition-all duration-500 cursor-grab active:cursor-grabbing hover:border-purple-400 ${
          isDragging ? 'opacity-20 scale-95 border-purple-500' : 'opacity-100'
        }`}
        onClick={() => handleProjectClick(project)}
      >
        <div className="relative aspect-video overflow-hidden border-b-2 border-slate-100">
          <img 
            src={displayImg} 
            alt={project.title}
            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-slate-950/0 group-hover:bg-purple-950/40 transition-all duration-500" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-500">
             <div 
               onClick={(e) => handlePlayVideo(project, e)}
               className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl scale-75 group-hover:scale-100 transition-transform duration-500 cursor-pointer hover:bg-slate-50 active:scale-90"
             >
               <div className="scale-125">{ICONS.Play}</div>
             </div>
          </div>
        </div>
        <div className="p-8">
          <div className="flex items-center gap-2 mb-4">
            <span className="px-3 py-1 bg-purple-700 text-white rounded-[1rem] text-[9px] font-black uppercase tracking-widest shadow-lg shadow-purple-200">
              {project.status}
            </span>
          </div>
          <h4 className="text-[16px] font-black text-slate-950 uppercase tracking-tight group-hover:text-purple-700 transition-colors line-clamp-2 leading-tight">
            {project.title}
          </h4>
          <div className="flex items-center justify-between mt-6 pt-6 border-t-2 border-slate-100">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{project.lastEdited}</span>
             <button 
               onClick={(e) => handlePlayVideo(project, e)}
               className="text-[10px] font-black text-purple-700 uppercase flex items-center gap-2 group-hover:translate-x-1 transition-transform hover:underline"
             >
               LEARN {ICONS.External}
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderAddPlaceholder = (trackId: string, subcategoryId?: string) => (
    <div 
      key={`add-${trackId}-${subcategoryId || 'main'}`}
      onClick={() => handleCreateProject(trackId, subcategoryId)}
      className="group aspect-video xl:aspect-auto xl:h-full min-h-[250px] border-4 border-dashed border-slate-200 rounded-[3.5rem] bg-white/50 flex flex-col items-center justify-center gap-4 hover:border-purple-600 hover:bg-purple-50 transition-all cursor-pointer shadow-sm hover:shadow-xl"
    >
      <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-purple-600 group-hover:text-white transition-all shadow-inner">
        <div className="scale-150 transition-transform group-hover:rotate-90">{ICONS.Plus}</div>
      </div>
      <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-purple-700 transition-colors">
        ADD TUTORIAL
      </span>
    </div>
  );

  const visibleTracks = selectedTrackId 
    ? tracks.filter(t => t.id === selectedTrackId)
    : tracks;

  const getBreadcrumbs = () => {
    const crumbs = [];
    crumbs.push(
      <button 
        key="all" 
        onClick={() => { setSelectedTrackId(null); setSelectedSubcategoryId(null); }}
        className="hover:text-purple-700 transition-colors"
      >
        LEARNING GALLERY
      </button>
    );

    if (selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      crumbs.push(<span key="s1" className="text-slate-300 mx-2">/</span>);
      crumbs.push(
        <button 
          key="track" 
          onClick={() => setSelectedSubcategoryId(null)}
          className={`hover:text-purple-700 transition-colors ${!selectedSubcategoryId ? 'text-purple-700' : ''}`}
        >
          {track?.title}
        </button>
      );
    }

    if (selectedSubcategoryId && selectedTrackId) {
      const track = tracks.find(t => t.id === selectedTrackId);
      const sub = track?.subcategories?.find(s => s.id === selectedSubcategoryId);
      crumbs.push(<span key="s2" className="text-slate-300 mx-2">/</span>);
      crumbs.push(<span key="sub" className="text-purple-700">{sub?.title}</span>);
    }

    return crumbs;
  };

  if (currentView === 'editor' && selectedProject) {
    return (
      <ProjectEditor 
        project={selectedProject} 
        tracks={tracks} 
        onSave={handleSaveProject} 
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }} 
      />
    );
  }

  if (currentView === 'viewer' && selectedProject) {
    return (
      <ProjectViewer 
        project={selectedProject}
        track={tracks.find(t => t.id === selectedProject.trackId)}
        onBack={() => { setCurrentView('home'); setSelectedProject(null); }}
        onEdit={() => setCurrentView('editor')}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden">
      <Sidebar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        tracks={tracks}
        onTracksReorder={setTracks}
        selectedTrackId={selectedTrackId}
        onTrackSelect={setSelectedTrackId}
        selectedSubcategoryId={selectedSubcategoryId}
        onSubcategorySelect={setSelectedSubcategoryId}
      />

      <main className="flex-1 flex flex-col relative overflow-y-auto px-12 py-12 scroll-smooth no-scrollbar">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-16">
          <div className="group">
            <h1 className="text-[42px] font-black text-slate-950 leading-tight uppercase tracking-tighter flex items-center flex-wrap">
              {getBreadcrumbs()}
            </h1>
            <p className="text-[14px] font-black text-purple-700 uppercase tracking-[0.3em] mt-1">
              EDUCATIONAL HUB • CURATED BY EXPERTS
            </p>
          </div>

          <div className="flex items-center gap-6">
            {(selectedTrackId || selectedSubcategoryId) && (
              <button 
                onClick={() => { 
                  if (selectedSubcategoryId) setSelectedSubcategoryId(null);
                  else setSelectedTrackId(null);
                }}
                className="text-[11px] font-black text-slate-500 hover:text-purple-700 uppercase tracking-widest flex items-center gap-2 transition-colors bg-white px-4 py-3 rounded-2xl border-2 border-slate-200 shadow-sm"
              >
                {ICONS.Back} GO BACK
              </button>
            )}
            <div className="relative w-80">
              <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600">
                {ICONS.Search}
              </div>
              <input 
                type="text" 
                placeholder="Search tutorials..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-14 pr-6 py-4 bg-white border-2 border-slate-300 rounded-[2rem] text-[14px] font-bold focus:outline-none focus:ring-4 focus:ring-purple-600/20 shadow-xl transition-all text-slate-950 placeholder:text-slate-500"
              />
            </div>
            <button 
              onClick={() => handleCreateProject()}
              className="flex items-center gap-3 bg-purple-700 text-white px-10 py-5 rounded-[2rem] text-[13px] font-black uppercase tracking-widest hover:bg-slate-950 shadow-2xl transition-all active:scale-95"
            >
              {ICONS.Plus} ADD TUTORIAL
            </button>
          </div>
        </header>

        <div className="space-y-32 pb-20">
          {visibleTracks.map((track) => {
            const trackProjects = filteredProjects.filter(p => p.trackId === track.id);
            const subcategoriesToRender = selectedSubcategoryId 
              ? track.subcategories?.filter(s => s.id === selectedSubcategoryId) 
              : track.subcategories;

            const hasSubcategories = subcategoriesToRender && subcategoriesToRender.length > 0;

            return (
              <section key={track.id} className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-700">
                {!selectedTrackId && (
                  <div 
                    className="flex items-center justify-between border-b-4 border-slate-200 pb-8 cursor-pointer group"
                    onClick={() => setSelectedTrackId(track.id)}
                  >
                    <div className="flex items-center gap-6">
                      <span className="text-5xl bg-white p-5 rounded-[2.5rem] shadow-xl border-2 border-slate-100 group-hover:scale-105 transition-transform">{track.icon}</span>
                      <div>
                        <h3 className="text-3xl font-black text-slate-950 uppercase tracking-tight leading-none group-hover:text-purple-700 transition-colors">
                          {track.title}
                        </h3>
                        <p className="text-[13px] font-black text-slate-600 uppercase tracking-[0.2em] mt-3">
                          {track.subtitle}
                        </p>
                      </div>
                    </div>
                  </div>
                )}

                {hasSubcategories ? (
                  <div className="space-y-16">
                    {subcategoriesToRender?.map(sub => {
                      const subProjects = trackProjects.filter(p => p.subcategoryId === sub.id);
                      return (
                        <div key={sub.id} className="space-y-8 pl-4 border-l-4 border-purple-100">
                          <h4 
                            className={`text-xl font-black uppercase tracking-widest flex items-center gap-4 cursor-pointer hover:text-purple-900 transition-colors ${selectedSubcategoryId === sub.id ? 'text-purple-900' : 'text-purple-700'}`}
                            onClick={() => setSelectedSubcategoryId(sub.id)}
                          >
                            <span className={`w-4 h-4 rounded-full ${selectedSubcategoryId === sub.id ? 'bg-purple-900 scale-125' : 'bg-purple-600'}`} />
                            {sub.title}
                          </h4>
                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                            {subProjects.map(project => renderProjectCard(project))}
                            {renderAddPlaceholder(track.id, sub.id)}
                          </div>
                        </div>
                      );
                    })}
                    {/* Projects in this track but without specific subcategory - only show if no specific subcategory is selected or if we're viewing all */}
                    {!selectedSubcategoryId && trackProjects.filter(p => !p.subcategoryId).length > 0 && (
                      <div className="space-y-8 pl-4">
                        <h4 className="text-xl font-black text-slate-400 uppercase tracking-widest">Other Tutorials</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                          {trackProjects.filter(p => !p.subcategoryId).map(project => renderProjectCard(project))}
                          {renderAddPlaceholder(track.id)}
                        </div>
                      </div>
                    )}
                  </div>
                ) : (
                  // Only show direct projects if no specific subcategory is requested or if track has no subcategories
                  (!selectedSubcategoryId) && (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-12">
                      {trackProjects.map((project) => renderProjectCard(project))}
                      {renderAddPlaceholder(track.id)}
                    </div>
                  )
                )}
              </section>
            );
          })}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ICONS } from '../constants';

interface VideoPlayerProps {
  url: string;
  className?: string;
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ url, className = "" }) => {
  const [isPlaying, setIsPlaying] = useState(false);

  const getYoutubeId = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      if (urlObj.hostname.includes('youtu.be')) return urlObj.pathname.slice(1);
      if (urlObj.hostname.includes('youtube.com')) return urlObj.searchParams.get('v');
    } catch (e) {}
    return null;
  };

  const getVimeoId = (videoUrl: string) => {
    try {
      const urlObj = new URL(videoUrl);
      if (urlObj.hostname.includes('vimeo.com')) return urlObj.pathname.split('/').pop();
    } catch (e) {}
    return null;
  };

  const ytId = getYoutubeId(url);
  const vimeoId = getVimeoId(url);

  const handlePlay = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (ytId || vimeoId) {
      setIsPlaying(true);
    } else {
      window.open(url, '_blank', 'noopener,noreferrer');
    }
  };

  if (isPlaying) {
    let embedSrc = '';
    if (ytId) embedSrc = `https://www.youtube.com/embed/${ytId}?autoplay=1`;
    else if (vimeoId) embedSrc = `https://player.vimeo.com/video/${vimeoId}?autoplay=1`;

    return (
      <div className={`relative aspect-video w-full rounded-[3.5rem] overflow-hidden bg-black shadow-2xl ${className}`}>
        <iframe
          src={embedSrc}
          className="absolute inset-0 w-full h-full border-0"
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
        ></iframe>
      </div>
    );
  }

  const thumbnail = ytId 
    ? `https://img.youtube.com/vi/${ytId}/maxresdefault.jpg`
    : "https://images.unsplash.com/photo-1611162617213-7d7a39e9b1d7?q=80&w=1000&auto=format&fit=crop";

  const platform = ytId ? 'YouTube' : vimeoId ? 'Vimeo' : 'Video';

  return (
    <div 
      onClick={handlePlay}
      className={`group relative aspect-video w-full rounded-[3.5rem] overflow-hidden bg-slate-900 cursor-pointer shadow-2xl transition-all hover:shadow-purple-500/40 border-4 border-transparent hover:border-purple-500/30 ${className}`}
    >
      <img 
        src={thumbnail} 
        className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110 opacity-60" 
        alt="Video content"
        onError={(e) => {
          if (ytId) (e.target as HTMLImageElement).src = `https://img.youtube.com/vi/${ytId}/hqdefault.jpg`;
        }}
      />

      <div className="absolute inset-0 bg-slate-950/20 group-hover:bg-slate-950/60 transition-all duration-500 flex flex-col items-center justify-center">
        <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center text-purple-700 shadow-2xl transform transition-all group-hover:scale-110 group-active:scale-95">
